  '2025-3-18': 'Wafat Yesus Kristus',
  '2025-3-20': 'Hari Paskah',
  '2025-4-1': 'Hari Buruh Internasional',
  '2025-4-12': 'Hari Raya Waisak 2569 BE',
  '2025-4-29': 'Kenaikan Yesus Kristus',
  '2025-5-1': 'Hari Lahir Pancasila',
  '2025-5-6': 'Hari Raya Idul Adha 1446 Hijriah',
  '2025-5-27': 'Tahun Baru Islam 1447 Hijriah',
  '2025-7-17': 'Hari Kemerdekaan RI',
  '2025-8-5': 'Maulid Nabi Muhammad SAW',
  '2025-11-25': 'Hari Raya Natal',
};

const App: React.FC = () => {
