                        rows={1}
                        value={act.description}
                        onChange={e => updateActivity(act.id, { description: e.target.value })}
                        onBlur={e => {
                          const val = e.target.value;
                          if (val.toLowerCase().includes('libur') || val.toLowerCase().includes('minggu')) {
                            updateActivity(act.id, { isHoliday: true, quantity: 'LU' });
                          } else if (val) {
                            updateActivity(act.id, { isHoliday: false, quantity: act.quantity === 'LU' ? '1 Kegiatan' : act.quantity });
                          }
                        }}
                        style={{ height: 'auto', minHeight: '40px' }}
                      />
                      {!act.isHoliday && act.description && (
                        <button 
                          onClick={() => handleRefine(act.id, act.description)}
                          className="absolute right-2 opacity-0 group-hover:opacity-100 transition p-1 bg-white rounded-md border shadow-sm text-indigo-500 no-print"
                          title="Perhalus dengan AI"
                        >
                          <Sparkles size={14} />
                        </button>
                      )}
                    </div>
                  </td>
                  <td className="border-2 border-black p-0">
                    <input 
                      className="w-full p-2 bg-transparent text-center border-none outline-none"
                      value={act.quantity}
                      onChange={e => updateActivity(act.id, { quantity: e.target.value })}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* Footer BCK */}
          <div className="mt-12 grid grid-cols-2 gap-20">
            <div className="text-center">
              <p className="mb-20">Mengetahui<br/>Kepala Madrasah</p>
              <p className="font-bold underline uppercase">{profile.headmasterName}</p>
            </div>
            <div className="text-center">
              <p className="mb-20">{profile.location}, {currentLog.activities[currentLog.activities.length - 1].date}<br/>Guru Kelas/Mapel</p>
              <p className="font-bold underline uppercase">{profile.name}</p>
            </div>
          </div>
        </div>
      </main>

      {/* Floating Info */}
      <div className="fixed bottom-4 right-4 no-print flex flex-col items-end space-y-2">
        <div className="bg-white border border-gray-200 px-4 py-2 rounded-2xl shadow-xl flex items-center gap-2 text-sm">
          <AlertCircle size={16} className="text-blue-500" />
          <span>Tip: Ketik "Libur" untuk menandai hari libur otomatis.</span>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Plus, 
  Trash2, 
  Printer, 
  Save, 
  User, 
  FileText, 
  Settings, 
