  X
} from 'lucide-react';
import { Profile, Activity, MonthlyLog } from './types';
import { suggestActivities, refineActivity } from './services/geminiService';

const STORAGE_KEY_PROFILE = 'bck_profile';
const STORAGE_KEY_LOGS = 'bck_logs';

// Indonesian National Holidays 2025
const NATIONAL_HOLIDAYS_2025: Record<string, string> = {
  '2025-0-1': 'Tahun Baru 2025 Masehi',
  '2025-0-27': 'Isra Mikraj Nabi Muhammad SAW',
  '2025-0-29': 'Tahun Baru Imlek 2576 Kongzili',
  '2025-2-29': 'Hari Suci Nyepi (Tahun Baru Saka 1947)',
  '2025-2-31': 'Idul Fitri 1446 Hijriah',
  '2025-3-1': 'Idul Fitri 1446 Hijriah',
  '2025-3-18': 'Wafat Yesus Kristus',
  '2025-3-20': 'Hari Paskah',
  '2025-4-1': 'Hari Buruh Internasional',
  '2025-4-12': 'Hari Raya Waisak 2569 BE',
  '2025-4-29': 'Kenaikan Yesus Kristus',
  '2025-5-1': 'Hari Lahir Pancasila',
  '2025-5-6': 'Hari Raya Idul Adha 1446 Hijriah',
  '2025-5-27': 'Tahun Baru Islam 1447 Hijriah',
  '2025-7-17': 'Hari Kemerdekaan RI',
  '2025-8-5': 'Maulid Nabi Muhammad SAW',
  '2025-11-25': 'Hari Raya Natal',
};

const App: React.FC = () => {
  const [profile, setProfile] = useState<Profile>({
    name: 'ALI MAKSUM, S.Pd.I',
    nuptk: '3641766668110012',
    npk: '7880990033017',
    pegId: '910',
    jabatan: "Guru Mata Pelajaran Qur'an Hadits",
    school: 'MTsS Darul Huda',
    headmasterName: 'SALAMET MOLYONO, S.Pd',
    location: 'Bondowoso',
  });

  const [currentDate, setCurrentDate] = useState(new Date());
  const [logs, setLogs] = useState<MonthlyLog[]>([]);
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isCalendarOpen, setIsCalendarOpen] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);

  // Load data
  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEY_PROFILE);
    if (savedProfile) setProfile(JSON.parse(savedProfile));

    const savedLogs = localStorage.getItem(STORAGE_KEY_LOGS);
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  // Save data
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_LOGS, JSON.stringify(logs));
  }, [logs]);

  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();

  const getDaysInMonth = (month: number, year: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;

        // Check for national holiday
        const dateKey = `${currentYear}-${currentMonth}-${i}`;
        const holidayName = NATIONAL_HOLIDAYS_2025[dateKey];
        const isHoliday = isSunday || !!holidayName;

        activities.push({
          id: dateKey,
          date: date.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
          description: isSunday ? 'Minggu' : (holidayName || ''),
          quantity: isHoliday ? 'LU' : '',
          isHoliday: isHoliday
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);

    if (logIndex === -1) {
      const newLog = { ...currentLog };
      newLog.activities = newLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs([...newLogs, newLog]);
    } else {
      newLogs[logIndex].activities = newLogs[logIndex].activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs(newLogs);
    }
  };

  const handleRefine = async (id: string, text: string) => {
    if (!text) return;
    setAiLoading(true);
    const refined = await refineActivity(text);
    updateActivity(id, { description: refined });
    setAiLoading(false);
  };

  const loadAiSuggestions = async () => {
    setAiLoading(true);
    const ideas = await suggestActivities(profile.jabatan, profile.school);
    if (ideas) setSuggestions(ideas);
    setAiLoading(false);
  };

  const changeMonth = (offset: number) => {
    setCurrentDate(new Date(currentYear, currentMonth + offset, 1));
  };

  const printReport = () => {
    window.print();
  };

  const CalendarModal = () => {
    const daysInMonth = getDaysInMonth(currentMonth, currentYear);
    const firstDayOfMonth = new Date(currentYear, currentMonth, 1).getDay();
    const days = Array.from({ length: daysInMonth }, (_, i) => i + 1);
    const blanks = Array.from({ length: firstDayOfMonth }, (_, i) => i);

    return (
      <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
        <div className="bg-white w-full max-w-4xl rounded-3xl shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[90vh]">
          {/* Calendar View */}
          <div className="flex-1 p-6 sm:p-8">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-2xl font-bold text-gray-800">Kalender Pendidikan</h2>
              <div className="flex items-center bg-gray-100 rounded-xl p-1">
                <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-white rounded-lg transition shadow-sm"><ChevronLeft size={20} /></button>
                <span className="px-4 font-bold text-gray-700 min-w-[140px] text-center capitalize">
                  {currentDate.toLocaleDateString('id-ID', { month: 'long', year: 'numeric' })}
                </span>
                <button onClick={() => changeMonth(1)} className="p-2 hover:bg-white rounded-lg transition shadow-sm"><ChevronRight size={20} /></button>
              </div>
            </div>

            <div className="grid grid-cols-7 gap-2 mb-2">
              {['Min', 'Sen', 'Sel', 'Rab', 'Kam', 'Jum', 'Sab'].map((d, i) => (
                <div key={d} className={`text-center text-xs font-bold uppercase py-2 ${i === 0 ? 'text-red-500' : 'text-gray-400'}`}>
                  {d}
                </div>
              ))}
            </div>

            <div className="grid grid-cols-7 gap-2">
              {blanks.map(b => <div key={`b-${b}`} className="aspect-square"></div>)}
              {days.map(d => {
                const dateKey = `${currentYear}-${currentMonth}-${d}`;
                const isHoliday = NATIONAL_HOLIDAYS_2025[dateKey];
                const isSunday = new Date(currentYear, currentMonth, d).getDay() === 0;
                return (
                  <div 
                    key={d} 
                    className={`aspect-square flex items-center justify-center rounded-xl text-sm font-medium transition-all relative group
                      ${isSunday || isHoliday ? 'bg-red-50 text-red-600' : 'bg-gray-50 text-gray-700 hover:bg-blue-50 hover:text-blue-600'}
                    `}
                  >
                    {d}
                    {isHoliday && (
                      <div className="absolute bottom-1 w-1 h-1 bg-red-400 rounded-full"></div>
                    )}
                    {isHoliday && (
                      <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-max max-w-[150px] bg-gray-800 text-white text-[10px] p-2 rounded shadow-xl opacity-0 group-hover:opacity-100 pointer-events-none transition z-10">
                        {isHoliday}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Holiday List */}
          <div className="w-full md:w-80 bg-gray-50 border-l border-gray-100 p-6 sm:p-8 overflow-y-auto">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold text-gray-500 uppercase tracking-wider text-xs">Libur Nasional 2025</h3>
              <button onClick={() => setIsCalendarOpen(false)} className="text-gray-400 hover:text-gray-800 md:hidden"><X size={24} /></button>
            </div>
            <div className="space-y-4">
              {Object.entries(NATIONAL_HOLIDAYS_2025).map(([key, name]) => {
                const [y, m, d] = key.split('-').map(Number);
                const date = new Date(y, m, d);
                const isCurrentMonth = m === currentMonth;
                return (
                  <div key={key} className={`flex flex-col p-3 rounded-xl transition ${isCurrentMonth ? 'bg-white shadow-sm ring-1 ring-blue-100' : 'opacity-60'}`}>
                    <span className="text-[10px] font-bold text-blue-600 uppercase mb-1">
                      {date.toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}
                    </span>
                    <span className="text-xs font-semibold text-gray-800 leading-tight">{name}</span>
                  </div>
