        {/* Suggestions Tray */}
        {suggestions.length > 0 && (
          <div className="mb-6 p-4 bg-indigo-50 border border-indigo-100 rounded-2xl no-print animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-3">
              <span className="text-sm font-bold text-indigo-700">Pilih ide kegiatan untuk ditambahkan:</span>
              <button onClick={() => setSuggestions([])} className="text-indigo-400 hover:text-indigo-600 text-sm">Sembunyikan</button>
            </div>
            <div className="flex flex-wrap gap-2">
              {suggestions.map((s, idx) => (
                <button 
                  key={idx} 
                  onClick={() => {
                    const firstEmpty = currentLog.activities.find(a => !a.description && !a.isHoliday);
                    if (firstEmpty) updateActivity(firstEmpty.id, { description: s, quantity: '1 Kegiatan' });
                  }}
                  className="bg-white border border-indigo-200 px-3 py-1.5 rounded-full text-sm text-indigo-600 hover:bg-indigo-600 hover:text-white transition shadow-sm"
