const STORAGE_KEY_PROFILE = 'bck_profile';
const STORAGE_KEY_LOGS = 'bck_logs';

const NATIONAL_HOLIDAYS_2025: Record<string, string> = {
  '2025-0-1': 'Tahun Baru 2025 Masehi',
  '2025-0-27': 'Isra Mikraj Nabi Muhammad SAW',
  '2025-0-29': 'Tahun Baru Imlek 2576 Kongzili',
  '2025-2-29': 'Hari Suci Nyepi (Tahun Baru Saka 1947)',
