const App: React.FC = () => {
  const [profile, setProfile] = useState<Profile>({
    name: 'ALI MAKSUM, S.Pd.I',
    nuptk: '3641766668110012',
    npk: '7880990033017',
    pegId: '910',
    jabatan: "Guru Mata Pelajaran Qur'an Hadits",
    school: 'MTsS Darul Huda',
    headmasterName: 'SALAMET MOLYONO, S.Pd',
    location: 'Bondowoso',
  });

  const [currentDate, setCurrentDate] = useState(new Date());
  const [logs, setLogs] = useState<MonthlyLog[]>([]);
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEY_PROFILE);
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    const savedLogs = localStorage.getItem(STORAGE_KEY_LOGS);
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_LOGS, JSON.stringify(logs));
  }, [logs]);

  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();

  const getDaysInMonth = (month: number, year: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;
        const dateKey = `${currentYear}-${currentMonth}-${i}`;
        const holidayName = NATIONAL_HOLIDAYS_2025[dateKey];
        const isHoliday = isSunday || !!holidayName;

        activities.push({
          id: dateKey,
          date: date.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
          description: isSunday ? 'Minggu' : (holidayName || ''),
          quantity: isHoliday ? 'LU' : '',
          isHoliday: isHoliday
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);

    if (logIndex === -1) {
      const newLog = { ...currentLog };
      newLog.activities = newLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs([...newLogs, newLog]);
    } else {
      newLogs[logIndex].activities = newLogs[logIndex].activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs(newLogs);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    const reader = new FileReader();
    reader.onload = async (e) => {
      const base64 = e.target?.result as string;
      const base64Data = base64.split(',')[1];

      const results = await scanCalendar(base64Data, file.type);
      if (results && Array.isArray(results)) {
        const newLogs = [...logs];

        results.forEach((item: {date: string, name: string}) => {
          const date = new Date(item.date);
          const m = date.getMonth();
          const y = date.getFullYear();
          const d = date.getDate();
          const id = `${y}-${m}-${d}`;

          let monthLog = newLogs.find(l => l.month === m && l.year === y);
          if (!monthLog) {
            // Initialize month if doesn't exist
            const daysCount = getDaysInMonth(m, y);
            const activities: Activity[] = [];
            for (let i = 1; i <= daysCount; i++) {
              const iterDate = new Date(y, m, i);
              const isSunday = iterDate.getDay() === 0;
              const dateKey = `${y}-${m}-${i}`;
              activities.push({
                id: dateKey,
                date: iterDate.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
                description: isSunday ? 'Minggu' : '',
                quantity: isSunday ? 'LU' : '',
                isHoliday: isSunday
              });
            }
            monthLog = { month: m, year: y, activities };
            newLogs.push(monthLog);
          }

          monthLog.activities = monthLog.activities.map(a => 
            a.id === id ? { ...a, description: item.name, isHoliday: true, quantity: 'LU' } : a
          );
        });

        setLogs(newLogs);
        alert(`Berhasil mengimpor ${results.length} agenda pendidikan!`);
      } else {
        alert("Gagal memindai file. Pastikan file berisi teks kalender yang jelas.");
      }
      setIsScanning(false);
    };
    reader.readAsDataURL(file);
  };

  const handleRefine = async (id: string, text: string) => {
    if (!text) return;
    setAiLoading(true);
    const refined = await refineActivity(text);
    updateActivity(id, { description: refined });
    setAiLoading(false);
  };

  const loadAiSuggestions = async () => {
    setAiLoading(true);
    const ideas = await suggestActivities(profile.jabatan, profile.school);
    if (ideas) setSuggestions(ideas);
    setAiLoading(false);
  };

  const changeMonth = (offset: number) => {
    setCurrentDate(new Date(currentYear, currentMonth + offset, 1));
  };

  const printReport = () => {
    window.print();
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="bg-blue-700 text-white shadow-lg no-print sticky top-0 z-50">
        <div className="container mx-auto px-4 py-4 flex flex-wrap items-center justify-between">
          <div className="flex items-center space-x-2">
            <FileText size={28} />
            <h1 className="text-xl font-bold tracking-tight">BCK Smart Log</h1>
          </div>
          <div className="flex items-center space-x-2 mt-2 sm:mt-0">
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept=".pdf,.jpg,.jpeg,.png" 
              onChange={handleFileUpload}
            />
             <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center space-x-1 hover:bg-blue-600 px-3 py-2 rounded-lg transition text-blue-100"
            >
              <Upload size={18} />
              <span className="hidden sm:inline">Import Kaldik</span>
            </button>
            <button 
              onClick={() => setIsEditingProfile(!isEditingProfile)}
              className="flex items-center space-x-1 hover:bg-blue-600 px-3 py-2 rounded-lg transition"
            >
              <Settings size={18} />
              <span className="hidden sm:inline">Profil</span>
            </button>
            <button 
              onClick={printReport}
              className="flex items-center space-x-1 bg-green-500 hover:bg-green-600 px-4 py-2 rounded-lg transition font-medium"
            >
              <Printer size={18} />
              <span>Cetak Laporan</span>
            </button>
          </div>
        </div>
      </header>

      {/* Scanning Overlay */}
      {isScanning && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 text-center">
          <div className="bg-white rounded-3xl p-8 max-w-sm shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="relative w-20 h-20 mx-auto mb-6">
              <Loader2 className="w-full h-full text-blue-600 animate-spin" />
              <Sparkles className="absolute top-0 right-0 text-yellow-400 animate-bounce" size={24} />
            </div>
            <h2 className="text-xl font-bold text-gray-800 mb-2">Memindai Dokumen...</h2>
            <p className="text-gray-500 text-sm leading-relaxed">
              Gemini AI sedang membaca kalender pendidikan Anda. Mohon tunggu sebentar.
            </p>
          </div>
        </div>
      )}

      <main className="container mx-auto px-4 py-8">
        {/* Profile Editor */}
        {isEditingProfile && (
          <div className="mb-8 bg-white p-6 rounded-2xl shadow-sm border border-gray-100 no-print animate-in fade-in slide-in-from-top-4 duration-300">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <User className="text-blue-600" />
                Pengaturan Profil & Header
