                    {key.replace(/([A-Z])/g, ' $1').trim()}
                  </label>
                  <input 
                    className="w-full bg-gray-50 border rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" 
                    value={(profile as any)[key]} 
                    onChange={e => setProfile({...profile, [key]: e.target.value})}
                  />
                </div>
              ))}
            </div>
          </div>
