            </div>
            <div className="flex">
              <div className="w-40 font-bold uppercase text-sm">RA/Madrasah</div>
              <div className="font-bold text-sm">: {profile.school}</div>
            </div>
          </div>

          <table className="w-full border-collapse border-2 border-black text-sm">
