export interface ScanInput {
  fileBase64?: string;
  mimeType?: string;
  extractedText?: string;
}

export const scanCalendar = async (input: ScanInput) => {
  if (!API_KEY) return null;

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const parts: any[] = [];

  if (input.fileBase64 && input.mimeType) {
    parts.push({
      inlineData: {
        data: input.fileBase64,
        mimeType: input.mimeType,
      },
    });
  }

  if (input.extractedText) {
    parts.push({
      text: `Data teks dari file Excel/Dokumen: \n${input.extractedText}`,
    });
  }

  parts.push({
    text: `Analisis data kalender pendidikan ini. Ekstrak daftar hari libur dan kegiatan penting untuk tahun ajaran 2025/2026. 
           Kembalikan dalam format JSON array dengan struktur: [{"date": "YYYY-MM-DD", "name": "Nama Libur/Kegiatan"}].
           Pastikan format tanggal adalah YYYY-MM-DD. Fokus pada hari libur resmi dan hari besar.`,
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [{ parts }],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            date: { type: Type.STRING },
            name: { type: Type.STRING },
          },
          required: ["date", "name"],
        },
      },
    },
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Failed to parse calendar scan", e);
    return null;
  }
};

