  FileText, 
  Settings, 
  Sparkles, 
  AlertCircle, 
  ChevronLeft, 
  ChevronRight,
  Upload,
  X,
  Loader2,
  CheckCircle2
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { Profile, Activity, MonthlyLog } from './types';
import { suggestActivities, refineActivity, scanCalendar } from './services/geminiService';

const STORAGE_KEY_PROFILE = 'bck_profile';
const STORAGE_KEY_LOGS = 'bck_logs';

const NATIONAL_HOLIDAYS_2025: Record<string, string> = {
  '2025-0-1': 'Tahun Baru 2025 Masehi',
  '2025-0-27': 'Isra Mikraj Nabi Muhammad SAW',
  '2025-0-29': 'Tahun Baru Imlek 2576 Kongzili',
  '2025-2-29': 'Hari Suci Nyepi (Tahun Baru Saka 1947)',
  '2025-2-31': 'Idul Fitri 1446 Hijriah',
  '2025-3-1': 'Idul Fitri 1446 Hijriah',
  '2025-3-18': 'Wafat Yesus Kristus',
  '2025-3-20': 'Hari Paskah',
  '2025-4-1': 'Hari Buruh Internasional',
  '2025-4-12': 'Hari Raya Waisak 2569 BE',
  '2025-4-29': 'Kenaikan Yesus Kristus',
  '2025-5-1': 'Hari Lahir Pancasila',
  '2025-5-6': 'Hari Raya Idul Adha 1446 Hijriah',
  '2025-5-27': 'Tahun Baru Islam 1447 Hijriah',
  '2025-7-17': 'Hari Kemerdekaan RI',
  '2025-8-5': 'Maulid Nabi Muhammad SAW',
  '2025-11-25': 'Hari Raya Natal',
};

const App: React.FC = () => {
  const [profile, setProfile] = useState<Profile>({
    name: 'ALI MAKSUM, S.Pd.I',
    nuptk: '3641766668110012',
    npk: '7880990033017',
    pegId: '910',
    jabatan: "Guru Mata Pelajaran Qur'an Hadits",
    school: 'MTsS Darul Huda',
    headmasterName: 'SALAMET MOLYONO, S.Pd',
    location: 'Bondowoso',
  });

  const [currentDate, setCurrentDate] = useState(new Date());
  const [logs, setLogs] = useState<MonthlyLog[]>([]);
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEY_PROFILE);
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    const savedLogs = localStorage.getItem(STORAGE_KEY_LOGS);
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_LOGS, JSON.stringify(logs));
  }, [logs]);

  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();

  const getDaysInMonth = (month: number, year: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;
        const dateKey = `${currentYear}-${currentMonth}-${i}`;
        const holidayName = NATIONAL_HOLIDAYS_2025[dateKey];
        const isHoliday = isSunday || !!holidayName;

        activities.push({
          id: dateKey,
          date: date.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
          description: isSunday ? 'Minggu' : (holidayName || ''),
          quantity: isHoliday ? 'LU' : '',
          isHoliday: isHoliday
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);

    if (logIndex === -1) {
      const newLog = { ...currentLog };
      newLog.activities = newLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs([...newLogs, newLog]);
    } else {
      newLogs[logIndex].activities = newLogs[logIndex].activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs(newLogs);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsScanning(true);

    try {
      if (file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' || file.name.endsWith('.xlsx')) {
        // Handle Excel Files
        const reader = new FileReader();
        reader.onload = async (e) => {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          const firstSheetName = workbook.SheetNames[0];
          const worksheet = workbook.Sheets[firstSheetName];
          const csvText = XLSX.utils.sheet_to_csv(worksheet);

          const results = await scanCalendar({ extractedText: csvText });
          processScanResults(results);
        };
        reader.readAsArrayBuffer(file);
      } else {
        // Handle PDF and Images (MIME types supported by Gemini natively)
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = e.target?.result as string;
          const base64Data = base64.split(',')[1];
          const results = await scanCalendar({ fileBase64: base64Data, mimeType: file.type });
          processScanResults(results);
        };
        reader.readAsDataURL(file);
      }
    } catch (err) {
      console.error(err);
      alert("Gagal memproses file. Pastikan format file benar.");
      setIsScanning(false);
    }
  };

  const processScanResults = (results: any) => {
    if (results && Array.isArray(results)) {
      const newLogs = [...logs];

      results.forEach((item: {date: string, name: string}) => {
        const date = new Date(item.date);
        const m = date.getMonth();
        const y = date.getFullYear();
        const d = date.getDate();
        const id = `${y}-${m}-${d}`;

        let monthLog = newLogs.find(l => l.month === m && l.year === y);
        if (!monthLog) {
          const daysCount = getDaysInMonth(m, y);
          const activities: Activity[] = [];
          for (let i = 1; i <= daysCount; i++) {
            const iterDate = new Date(y, m, i);
            const isSunday = iterDate.getDay() === 0;
            const dateKey = `${y}-${m}-${i}`;
            activities.push({
              id: dateKey,
              date: iterDate.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
              description: isSunday ? 'Minggu' : '',
              quantity: isSunday ? 'LU' : '',
              isHoliday: isSunday
            });
          }
          monthLog = { month: m, year: y, activities };
          newLogs.push(monthLog);
        }

        monthLog.activities = monthLog.activities.map(a => 
          a.id === id ? { ...a, description: item.name, isHoliday: true, quantity: 'LU' } : a
        );
      });

      setLogs(newLogs);
      alert(`Berhasil mengimpor ${results.length} agenda pendidikan!`);
    } else {
      alert("Gagal memindai file. Pastikan file berisi teks kalender yang jelas.");
    }
    setIsScanning(false);
  };

  const handleRefine = async (id: string, text: string) => {
    if (!text) return;
    setAiLoading(true);
    const refined = await refineActivity(text);
    updateActivity(id, { description: refined });
    setAiLoading(false);
  };

  const loadAiSuggestions = async () => {
    setAiLoading(true);
    const ideas = await suggestActivities(profile.jabatan, profile.school);
    if (ideas) setSuggestions(ideas);
    setAiLoading(false);
  };

  const changeMonth = (offset: number) => {
    setCurrentDate(new Date(currentYear, currentMonth + offset, 1));
  };

  const printReport = () => {
    window.print();
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="bg-blue-700 text-white shadow-lg no-print sticky top-0 z-50">
        <div className="container mx-auto px-4 py-4 flex flex-wrap items-center justify-between">
          <div className="flex items-center space-x-2">
            <FileText size={28} />
            <h1 className="text-xl font-bold tracking-tight">BCK Smart Log</h1>
          </div>
          <div className="flex items-center space-x-2 mt-2 sm:mt-0">
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept=".pdf,.jpg,.jpeg,.png,.xlsx" 
              onChange={handleFileUpload}
            />
             <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center space-x-1 hover:bg-blue-600 px-3 py-2 rounded-lg transition text-blue-100"
            >
              <Upload size={18} />
              <span className="hidden sm:inline">Import Kaldik</span>
            </button>
            <button 
              onClick={() => setIsEditingProfile(!isEditingProfile)}
              className="flex items-center space-x-1 hover:bg-blue-600 px-3 py-2 rounded-lg transition"
            >
              <Settings size={18} />
              <span className="hidden sm:inline">Profil</span>
            </button>
            <button 
              onClick={printReport}
              className="flex items-center space-x-1 bg-green-500 hover:bg-green-600 px-4 py-2 rounded-lg transition font-medium"
            >
              <Printer size={18} />
              <span>Cetak Laporan</span>
            </button>
          </div>
        </div>
      </header>

      {/* Scanning Overlay */}
      {isScanning && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 text-center">
          <div className="bg-white rounded-3xl p-8 max-w-sm shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="relative w-20 h-20 mx-auto mb-6">
              <Loader2 className="w-full h-full text-blue-600 animate-spin" />
              <Sparkles className="absolute top-0 right-0 text-yellow-400 animate-bounce" size={24} />
            </div>
            <h2 className="text-xl font-bold text-gray-800 mb-2">Memindai Dokumen...</h2>
            <p className="text-gray-500 text-sm leading-relaxed">
              Gemini AI sedang membaca kalender pendidikan Anda. Mohon tunggu sebentar.
            </p>
          </div>
        </div>
      )}

      <main className="container mx-auto px-4 py-8">
        {/* Profile Editor */}
        {isEditingProfile && (
          <div className="mb-8 bg-white p-6 rounded-2xl shadow-sm border border-gray-100 no-print animate-in fade-in slide-in-from-top-4 duration-300">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <User className="text-blue-600" />
                Pengaturan Profil & Header
              </h2>
              <button onClick={() => setIsEditingProfile(false)} className="text-gray-400 hover:text-gray-600">
                <X size={20} />
              </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {['name', 'nuptk', 'npk', 'pegId', 'jabatan', 'school', 'headmasterName', 'location'].map((key) => (
                <div key={key}>
                  <label className="block text-xs font-semibold text-gray-500 mb-1 capitalize">
                    {key.replace(/([A-Z])/g, ' $1').trim()}
                  </label>
                  <input 
                    className="w-full bg-gray-50 border rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" 
                    value={(profile as any)[key]} 
                    onChange={e => setProfile({...profile, [key]: e.target.value})}
                  />
                </div>
              ))}
            </div>
          </div>
        )}

        {/* AI Tools Section */}
        <div className="mb-6 flex flex-wrap items-center justify-between gap-4 no-print">
          <div className="flex items-center bg-white border border-gray-200 rounded-2xl p-1 shadow-sm">
            <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-gray-100 rounded-xl transition"><ChevronLeft size={20} /></button>
            <div className="px-6 font-bold text-gray-700 capitalize">
              {currentDate.toLocaleDateString('id-ID', { month: 'long', year: 'numeric' })}
            </div>
            <button onClick={() => changeMonth(1)} className="p-2 hover:bg-gray-100 rounded-xl transition"><ChevronRight size={20} /></button>
          </div>

          <div className="flex space-x-2">
            <button 
              onClick={loadAiSuggestions}
              disabled={aiLoading}
              className="flex items-center space-x-2 bg-gradient-to-r from-purple-600 to-indigo-600 text-white px-5 py-2.5 rounded-xl shadow-md hover:shadow-lg transition disabled:opacity-50"
            >
              <Sparkles size={18} />
              <span>{aiLoading ? 'Berpikir...' : 'Ide Kegiatan (AI)'}</span>
            </button>
          </div>
        </div>

        {/* Suggestions Tray */}
        {suggestions.length > 0 && (
          <div className="mb-6 p-4 bg-indigo-50 border border-indigo-100 rounded-2xl no-print animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-3">
              <span className="text-sm font-bold text-indigo-700">Pilih ide kegiatan untuk ditambahkan:</span>
              <button onClick={() => setSuggestions([])} className="text-indigo-400 hover:text-indigo-600 text-sm">Sembunyikan</button>
            </div>
            <div className="flex flex-wrap gap-2">
              {suggestions.map((s, idx) => (
                <button 
                  key={idx} 
                  onClick={() => {
                    const firstEmpty = currentLog.activities.find(a => !a.description && !a.isHoliday);
                    if (firstEmpty) updateActivity(firstEmpty.id, { description: s, quantity: '1 Kegiatan' });
                  }}
                  className="bg-white border border-indigo-200 px-3 py-1.5 rounded-full text-sm text-indigo-600 hover:bg-indigo-600 hover:text-white transition shadow-sm"
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* The Paper / Table */}
        <div className="bg-white shadow-2xl rounded-sm p-4 sm:p-10 border border-gray-200 overflow-x-auto min-w-full lg:min-w-[800px]">
          {/* Header BCK */}
          <div className="mb-6 space-y-1">
            <div className="flex">
              <div className="w-40 font-bold uppercase text-sm">Nama</div>
              <div className="font-bold text-sm">: {profile.name}</div>
            </div>
            <div className="flex">
              <div className="w-40 font-bold uppercase text-sm">NUPTK/NPK/Peg.id</div>
              <div className="font-bold text-sm">: {profile.nuptk} / {profile.npk} / {profile.pegId}</div>
            </div>
            <div className="flex">
              <div className="w-40 font-bold uppercase text-sm">Jabatan</div>
              <div className="font-bold text-sm">: {profile.jabatan}</div>
            </div>
            <div className="flex">
              <div className="w-40 font-bold uppercase text-sm">RA/Madrasah</div>
              <div className="font-bold text-sm">: {profile.school}</div>
            </div>
          </div>

          <table className="w-full border-collapse border-2 border-black text-sm">
            <thead>
              <tr className="bg-yellow-400">
                <th className="border-2 border-black p-2 w-12 text-center">NO</th>
                <th className="border-2 border-black p-2 w-48 text-center uppercase">Tanggal Kegiatan</th>
                <th className="border-2 border-black p-2 text-center uppercase">Kegiatan Harian</th>
                <th className="border-2 border-black p-2 w-32 text-center uppercase">Kuantitas</th>
              </tr>
            </thead>
            <tbody>
              {currentLog.activities.map((act, idx) => (
                <tr key={act.id} className={`${act.isHoliday ? 'bg-gray-300 font-medium' : ''}`}>
                  <td className="border-2 border-black p-2 text-center">{idx + 1}</td>
                  <td className="border-2 border-black p-2 text-center">{act.date}</td>
                  <td className="border-2 border-black p-0 group relative">
                    <div className="flex items-center">
                      <textarea 
                        className={`w-full p-2 bg-transparent resize-none outline-none border-none overflow-hidden ${act.isHoliday ? 'text-center' : ''}`}
                        rows={1}
                        value={act.description}
                        onChange={e => updateActivity(act.id, { description: e.target.value })}
                        onBlur={e => {
                          const val = e.target.value;
                          if (val.toLowerCase().includes('libur') || val.toLowerCase().includes('minggu')) {
                            updateActivity(act.id, { isHoliday: true, quantity: 'LU' });
                          } else if (val) {
                            updateActivity(act.id, { isHoliday: false, quantity: act.quantity === 'LU' ? '1 Kegiatan' : act.quantity });
                          }
                        }}
                        style={{ height: 'auto', minHeight: '40px' }}
                      />
                      {!act.isHoliday && act.description && (
                        <button 
                          onClick={() => handleRefine(act.id, act.description)}
                          className="absolute right-2 opacity-0 group-hover:opacity-100 transition p-1 bg-white rounded-md border shadow-sm text-indigo-500 no-print"
                        >
                          <Sparkles size={14} />
                        </button>
                      )}
                    </div>
                  </td>
                  <td className="border-2 border-black p-0">
                    <input 
                      className="w-full p-2 bg-transparent text-center border-none outline-none"
                      value={act.quantity}
                      onChange={e => updateActivity(act.id, { quantity: e.target.value })}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* Footer */}
          <div className="mt-12 grid grid-cols-2 gap-20">
            <div className="text-center">
              <p className="mb-20">Mengetahui<br/>Kepala Madrasah</p>
              <p className="font-bold underline uppercase">{profile.headmasterName}</p>
            </div>
            <div className="text-center">
              <p className="mb-20">{profile.location}, {currentLog.activities[currentLog.activities.length - 1].date}<br/>Guru Kelas/Mapel</p>
              <p className="font-bold underline uppercase">{profile.name}</p>
            </div>
          </div>
        </div>
      </main>

      <div className="fixed bottom-4 right-4 no-print flex flex-col items-end space-y-2">
        <div className="bg-white border border-gray-200 px-4 py-2 rounded-2xl shadow-xl flex items-center gap-2 text-sm">
          <AlertCircle size={16} className="text-blue-500" />
          <span>Tip: Gunakan "Import Kaldik" untuk memindai jadwal otomatis dari PDF atau Excel.</span>
        </div>
      </div>
    </div>
  );
};

export default App;

export interface Profile {
  name: string;
  nuptk: string;
  npk: string;
  pegId: string;
  jabatan: string;
  school: string;
  headmasterName: string;
  location: string;
}

export interface Activity {
  id: string;
  date: string;
  description: string;
  quantity: string;
  isHoliday: boolean;
}

export interface MonthlyLog {
  month: number;
  year: number;
  activities: Activity[];
}

export interface KaldikEvent {
  date: string; // YYYY-MM-DD
  name: string;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  Plus, 
  Trash2, 
  Printer, 
  Save, 
  User, 
  FileText, 
  Settings, 
  Sparkles, 
  AlertCircle, 
  ChevronLeft, 
  ChevronRight,
  Upload,
  X,
  Loader2,
  CheckCircle2,
  Calendar as CalendarIcon,
  ArrowLeft,
  Check,
  CalendarDays
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { Profile, Activity, MonthlyLog, KaldikEvent } from './types';
import { suggestActivities, refineActivity, scanCalendar } from './services/geminiService';

const STORAGE_KEY_PROFILE = 'bck_profile';
const STORAGE_KEY_LOGS = 'bck_logs';
const STORAGE_KEY_KALDIK = 'bck_kaldik_data';

const App: React.FC = () => {
  const [view, setView] = useState<'main' | 'kaldik'>('main');
  const [profile, setProfile] = useState<Profile>({
    name: 'ALI MAKSUM, S.Pd.I',
    nuptk: '3641766668110012',
    npk: '7880990033017',
    pegId: '910',
    jabatan: "Guru Mata Pelajaran Qur'an Hadits",
    school: 'MTsS Darul Huda',
    headmasterName: 'SALAMET MOLYONO, S.Pd',
    location: 'Bondowoso',
  });

  const [currentDate, setCurrentDate] = useState(new Date());
  const [logs, setLogs] = useState<MonthlyLog[]>([]);
  const [importedKaldik, setImportedKaldik] = useState<KaldikEvent[]>([]);
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load data
  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEY_PROFILE);
    if (savedProfile) setProfile(JSON.parse(savedProfile));

    const savedLogs = localStorage.getItem(STORAGE_KEY_LOGS);
    if (savedLogs) setLogs(JSON.parse(savedLogs));

    const savedKaldik = localStorage.getItem(STORAGE_KEY_KALDIK);
    if (savedKaldik) setImportedKaldik(JSON.parse(savedKaldik));
  }, []);

  // Save data
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_LOGS, JSON.stringify(logs));
  }, [logs]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_KALDIK, JSON.stringify(importedKaldik));
  }, [importedKaldik]);

  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();

  const getDaysInMonth = (month: number, year: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;
        const dateKey = `${currentYear}-${currentMonth + 1}-${i < 10 ? '0' + i : i}`; // Match YYYY-MM-DD roughly for lookup
        const standardDateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${i.toString().padStart(2, '0')}`;

        // Check imported Kaldik first
        const kaldikEvent = importedKaldik.find(e => e.date === standardDateStr);

        activities.push({
          id: `${currentYear}-${currentMonth}-${i}`,
          date: date.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
          description: kaldikEvent ? kaldikEvent.name : (isSunday ? 'Minggu' : ''),
          quantity: (isSunday || kaldikEvent) ? 'LU' : '',
          isHoliday: isSunday || !!kaldikEvent
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear, importedKaldik]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);

    if (logIndex === -1) {
      const newLog = { ...currentLog };
      newLog.activities = newLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs([...newLogs, newLog]);
    } else {
      newLogs[logIndex].activities = newLogs[logIndex].activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs(newLogs);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    try {
      if (file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' || file.name.endsWith('.xlsx')) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          const csvText = XLSX.utils.sheet_to_csv(workbook.Sheets[workbook.SheetNames[0]]);
          const results = await scanCalendar({ extractedText: csvText });
          if (results) setImportedKaldik(results);
          setIsScanning(false);
        };
        reader.readAsArrayBuffer(file);
      } else {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = (e.target?.result as string).split(',')[1];
          const results = await scanCalendar({ fileBase64: base64, mimeType: file.type });
          if (results) setImportedKaldik(results);
          setIsScanning(false);
        };
        reader.readAsDataURL(file);
      }
    } catch (err) {
      console.error(err);
      alert("Gagal memproses file.");
      setIsScanning(false);
    }
  };

  const applyKaldikToLogs = () => {
    if (importedKaldik.length === 0) {
      alert("Belum ada data kaldik yang diimport.");
      return;
    }

    // Reset current month logs to ensure they get the new kaldik data
    // Or we can smartly merge. For now, let's merge by checking the dates.
    const newLogs = [...logs];

    importedKaldik.forEach(event => {
      const [y, m, d] = event.date.split('-').map(Number);
      const monthIndex = m - 1;
      const dateId = `${y}-${monthIndex}-${d}`;

