import { suggestActivities, refineActivity, scanCalendar } from './services/geminiService';

const STORAGE_KEY_PROFILE = 'bck_profile';
const STORAGE_KEY_LOGS = 'bck_logs';
const STORAGE_KEY_KALDIK = 'bck_kaldik_data';

const App: React.FC = () => {
  const [view, setView] = useState<'main' | 'kaldik'>('main');
  const [profile, setProfile] = useState<Profile>({
    name: 'ALI MAKSUM, S.Pd.I',
    nuptk: '3641766668110012',
    npk: '7880990033017',
    pegId: '910',
    jabatan: "Guru Mata Pelajaran Qur'an Hadits",
    school: 'MTsS Darul Huda',
    headmasterName: 'SALAMET MOLYONO, S.Pd',
    location: 'Bondowoso',
  });

  const [currentDate, setCurrentDate] = useState(new Date());
  const [logs, setLogs] = useState<MonthlyLog[]>([]);
  const [importedKaldik, setImportedKaldik] = useState<KaldikEvent[]>([]);
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load data
  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEY_PROFILE);
    if (savedProfile) setProfile(JSON.parse(savedProfile));

    const savedLogs = localStorage.getItem(STORAGE_KEY_LOGS);
    if (savedLogs) setLogs(JSON.parse(savedLogs));

    const savedKaldik = localStorage.getItem(STORAGE_KEY_KALDIK);
    if (savedKaldik) setImportedKaldik(JSON.parse(savedKaldik));
  }, []);

  // Save data
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_LOGS, JSON.stringify(logs));
  }, [logs]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_KALDIK, JSON.stringify(importedKaldik));
  }, [importedKaldik]);

  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();

  const getDaysInMonth = (month: number, year: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;
        const standardDateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${i.toString().padStart(2, '0')}`;

        // Check imported Kaldik first
        const kaldikEvent = importedKaldik.find(e => e.date === standardDateStr);

        activities.push({
          id: `${currentYear}-${currentMonth}-${i}`,
          date: date.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
          description: kaldikEvent ? kaldikEvent.name : (isSunday ? 'Minggu' : ''),
          quantity: (isSunday || kaldikEvent) ? 'LU' : '',
          isHoliday: isSunday || !!kaldikEvent
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear, importedKaldik]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);

    if (logIndex === -1) {
      const newLog = { ...currentLog };
      newLog.activities = newLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs([...newLogs, newLog]);
    } else {
      newLogs[logIndex].activities = newLogs[logIndex].activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs(newLogs);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    try {
      if (file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' || file.name.endsWith('.xlsx')) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          const csvText = XLSX.utils.sheet_to_csv(workbook.Sheets[workbook.SheetNames[0]]);
          const results = await scanCalendar({ extractedText: csvText });
          if (results) setImportedKaldik(results);
          setIsScanning(false);
        };
        reader.readAsArrayBuffer(file);
      } else {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = (e.target?.result as string).split(',')[1];
          const results = await scanCalendar({ fileBase64: base64, mimeType: file.type });
          if (results) setImportedKaldik(results);
          setIsScanning(false);
        };
        reader.readAsDataURL(file);
      }
    } catch (err) {
      console.error(err);
      alert("Gagal memproses file.");
      setIsScanning(false);
    }
  };

  const applyKaldikToLogs = () => {
    if (importedKaldik.length === 0) {
      alert("Belum ada data kaldik yang diimport.");
      return;
    }

    const newLogs = [...logs];

    importedKaldik.forEach(event => {
      const [y, m, d] = event.date.split('-').map(Number);
      const monthIndex = m - 1;
      const dateId = `${y}-${monthIndex}-${d}`;

      let targetLog = newLogs.find(l => l.month === monthIndex && l.year === y);
      if (!targetLog) {
          const daysCount = getDaysInMonth(monthIndex, y);
          const activities: Activity[] = [];
          for (let i = 1; i <= daysCount; i++) {
            const iterDate = new Date(y, monthIndex, i);
            const isSun = iterDate.getDay() === 0;
            activities.push({
              id: `${y}-${monthIndex}-${i}`,
              date: iterDate.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
              description: isSun ? 'Minggu' : '',
              quantity: isSun ? 'LU' : '',
              isHoliday: isSun
            });
          }
          targetLog = { month: monthIndex, year: y, activities };
          newLogs.push(targetLog);
      }

      targetLog.activities = targetLog.activities.map(a => 
        (a.id === dateId || a.id === `${y}-${monthIndex}-${d}`) 
          ? { ...a, description: event.name, isHoliday: true, quantity: 'LU' } 
          : a
      );
    });

    setLogs(newLogs);
    alert("Data Kalender Pendidikan telah diterapkan ke seluruh tabel BCK.");
    setView('main');
  };

  const handleRefine = async (id: string, text: string) => {
    if (!text) return;
    setAiLoading(true);
    const refined = await refineActivity(text);
    updateActivity(id, { description: refined });
    setAiLoading(false);
  };

  const changeMonth = (offset: number) => {
    setCurrentDate(new Date(currentYear, currentMonth + offset, 1));
  };

  // Added printReport function to handle printing the document
  const printReport = () => {
    window.print();
  };

  const MainView = () => (
    <div className="animate-in fade-in slide-in-from-left-4 duration-300">
        {/* Profile Editor */}
        {isEditingProfile && (
          <div className="mb-8 bg-white p-6 rounded-2xl shadow-sm border border-gray-100 no-print">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <User className="text-blue-600" />
                Pengaturan Profil & Header
              </h2>
              <button onClick={() => setIsEditingProfile(false)} className="text-gray-400 hover:text-gray-600">
                <X size={20} />
              </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {Object.keys(profile).map((key) => (
                <div key={key}>
                  <label className="block text-xs font-semibold text-gray-500 mb-1 capitalize">
                    {key.replace(/([A-Z])/g, ' $1').trim()}
                  </label>
                  <input 
                    className="w-full bg-gray-50 border rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" 
                    value={(profile as any)[key]} 
                    onChange={e => setProfile({...profile, [key as keyof Profile]: e.target.value})}
                  />
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Navigation & AI */}
        <div className="mb-6 flex flex-wrap items-center justify-between gap-4 no-print">
          <div className="flex items-center bg-white border border-gray-200 rounded-2xl p-1 shadow-sm">
            <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-gray-100 rounded-xl transition"><ChevronLeft size={20} /></button>
            <div className="px-6 font-bold text-gray-700 capitalize">
              {currentDate.toLocaleDateString('id-ID', { month: 'long', year: 'numeric' })}
            </div>
            <button onClick={() => changeMonth(1)} className="p-2 hover:bg-gray-100 rounded-xl transition"><ChevronRight size={20} /></button>
          </div>

          <button 
            onClick={async () => {
              setAiLoading(true);
              const ideas = await suggestActivities(profile.jabatan, profile.school);
              if (ideas) setSuggestions(ideas);
              setAiLoading(false);
            }}
            disabled={aiLoading}
            className="flex items-center space-x-2 bg-indigo-600 text-white px-5 py-2.5 rounded-xl shadow-md hover:shadow-lg transition disabled:opacity-50"
          >
            <Sparkles size={18} />
            <span>{aiLoading ? 'Berpikir...' : 'Ide Kegiatan (AI)'}</span>
          </button>
        </div>

        {/* Suggestions Tray */}
        {suggestions.length > 0 && (
          <div className="mb-6 p-4 bg-indigo-50 border border-indigo-100 rounded-2xl no-print animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-3">
              <span className="text-sm font-bold text-indigo-700">Pilih ide kegiatan:</span>
              <button onClick={() => setSuggestions([])} className="text-indigo-400 hover:text-indigo-600 text-sm">Sembunyikan</button>
            </div>
            <div className="flex flex-wrap gap-2">
              {suggestions.map((s, idx) => (
                <button 
                  key={idx} 
                  onClick={() => {
                    const firstEmpty = currentLog.activities.find(a => !a.description && !a.isHoliday);
                    if (firstEmpty) updateActivity(firstEmpty.id, { description: s, quantity: '1 Kegiatan' });
                  }}
                  className="bg-white border border-indigo-200 px-3 py-1.5 rounded-full text-sm text-indigo-600 hover:bg-indigo-600 hover:text-white transition"
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* The BCK Paper */}
        <div className="bg-white shadow-2xl rounded-sm p-4 sm:p-10 border border-gray-200 overflow-x-auto">
          <div className="mb-6 space-y-1">
            <div className="flex"><div className="w-40 font-bold text-sm">NAMA</div><div className="font-bold text-sm">: {profile.name}</div></div>
            <div className="flex"><div className="w-40 font-bold text-sm">NUPTK/NPK/PEG.ID</div><div className="font-bold text-sm">: {profile.nuptk} / {profile.npk} / {profile.pegId}</div></div>
            <div className="flex"><div className="w-40 font-bold text-sm">JABATAN</div><div className="font-bold text-sm">: {profile.jabatan}</div></div>
            <div className="flex"><div className="w-40 font-bold text-sm">RA/MADRASAH</div><div className="font-bold text-sm">: {profile.school}</div></div>
          </div>

          <table className="w-full border-collapse border-2 border-black text-sm">
            <thead className="bg-yellow-400">
              <tr>
                <th className="border-2 border-black p-2 w-12 text-center">NO</th>
                <th className="border-2 border-black p-2 w-48 text-center">TANGGAL KEGIATAN</th>
                <th className="border-2 border-black p-2 text-center">KEGIATAN HARIAN</th>
                <th className="border-2 border-black p-2 w-32 text-center">KUANTITAS</th>
              </tr>
            </thead>
            <tbody>
              {currentLog.activities.map((act, idx) => (
                <tr key={act.id} className={`${act.isHoliday ? 'bg-gray-200' : ''}`}>
                  <td className="border-2 border-black p-2 text-center">{idx + 1}</td>
                  <td className="border-2 border-black p-2 text-center">{act.date}</td>
                  <td className="border-2 border-black p-0 group relative">
                    <div className="flex items-center">
                      <textarea 
                        className="w-full p-2 bg-transparent resize-none outline-none border-none overflow-hidden"
                        rows={1}
                        value={act.description}
                        onChange={e => updateActivity(act.id, { description: e.target.value })}
                        style={{ height: 'auto', minHeight: '40px' }}
                      />
                      {!act.isHoliday && act.description && (
                        <button 
                          onClick={() => handleRefine(act.id, act.description)}
                          className="absolute right-2 opacity-0 group-hover:opacity-100 transition p-1 bg-white rounded-md border shadow-sm text-indigo-500 no-print"
                        >
                          <Sparkles size={14} />
                        </button>
                      )}
                    </div>
                  </td>
                  <td className="border-2 border-black p-0 text-center">
                    <input 
                      className="w-full p-2 bg-transparent text-center border-none outline-none"
                      value={act.quantity}
                      onChange={e => updateActivity(act.id, { quantity: e.target.value })}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="mt-12 grid grid-cols-2 gap-20">
            <div className="text-center">
              <p className="mb-20">Mengetahui<br/>Kepala Madrasah</p>
              <p className="font-bold underline uppercase">{profile.headmasterName}</p>
            </div>
            <div className="text-center">
              <p className="mb-20">{profile.location}, {currentLog.activities[currentLog.activities.length - 1].date}<br/>Guru Kelas/Mapel</p>
              <p className="font-bold underline uppercase">{profile.name}</p>
            </div>
          </div>
        </div>
    </div>
  );

  const KaldikView = () => (
    <div className="animate-in fade-in slide-in-from-right-4 duration-300">
      <div className="flex items-center justify-between mb-8">
        <button 
          onClick={() => setView('main')}
          className="flex items-center gap-2 text-gray-500 hover:text-blue-600 transition font-medium"
        >
          <ArrowLeft size={20} />
          <span>Kembali ke BCK</span>
        </button>
        <h2 className="text-2xl font-bold text-gray-800">Manajemen Kalender Pendidikan</h2>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
            <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
              <Upload size={18} className="text-blue-600" />
              Import File Kaldik
            </h3>
            <p className="text-sm text-gray-500 mb-6">
              Unggah file PDF atau Excel (.xlsx) kalender pendidikan tahun ajaran berjalan. AI akan memindai hari libur otomatis.
            </p>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept=".pdf,.xlsx,.jpg,.png" 
              onChange={handleFileUpload}
            />
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white py-4 rounded-2xl transition font-bold shadow-lg shadow-blue-100"
            >
              <Upload size={20} />
              <span>Pilih Dokumen</span>
            </button>
          </div>

          {importedKaldik.length > 0 && (
            <div className="bg-indigo-600 p-6 rounded-3xl shadow-xl text-white">
              <h3 className="font-bold mb-2 flex items-center gap-2">
                <CheckCircle2 size={18} />
                Siap Diterapkan
              </h3>
              <p className="text-xs text-indigo-100 mb-6">
                {importedKaldik.length} agenda ditemukan. Tekan tombol di bawah untuk memasukkan data ini ke dalam tabel BCK Guru.
              </p>
              <button 
                onClick={applyKaldikToLogs}
                className="w-full bg-white text-indigo-600 hover:bg-indigo-50 py-3 rounded-xl transition font-bold"
              >
                Terapkan ke BCK
              </button>
            </div>
          )}
        </div>

        <div className="lg:col-span-2">
          <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-6 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
              <h3 className="font-bold text-gray-800 flex items-center gap-2">
                <CalendarDays size={18} className="text-blue-600" />
                Data Agenda Terdeteksi
              </h3>
              <button 
                onClick={() => setImportedKaldik([])}
                className="text-xs text-red-500 hover:underline"
              >
                Hapus Semua
              </button>
            </div>
            <div className="max-h-[600px] overflow-y-auto">
              {importedKaldik.length === 0 ? (
                <div className="p-20 text-center flex flex-col items-center">
                  <CalendarIcon size={48} className="text-gray-200 mb-4" />
                  <p className="text-gray-400 font-medium">Belum ada data yang diimport.</p>
                </div>
              ) : (
                <div className="divide-y divide-gray-50">
                  {importedKaldik.map((event, idx) => (
                    <div key={idx} className="p-4 flex items-center justify-between hover:bg-gray-50 transition">
                      <div className="flex items-center gap-4">
                        <div className="bg-blue-50 text-blue-600 p-2 rounded-lg font-bold text-xs w-24 text-center">
                          {new Date(event.date).toLocaleDateString('id-ID', { day: 'numeric', month: 'short', year: 'numeric' })}
                        </div>
                        <span className="text-sm font-semibold text-gray-700">{event.name}</span>
                      </div>
                      <button 
                        onClick={() => setImportedKaldik(importedKaldik.filter((_, i) => i !== idx))}
                        className="text-gray-300 hover:text-red-500 transition"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen pb-20">
      <header className="bg-blue-700 text-white shadow-lg no-print sticky top-0 z-50">
        <div className="container mx-auto px-4 py-4 flex flex-wrap items-center justify-between">
          <div className="flex items-center space-x-2 cursor-pointer" onClick={() => setView('main')}>
            <FileText size={28} />
            <h1 className="text-xl font-bold tracking-tight">BCK Smart Log</h1>
          </div>
          <div className="flex items-center space-x-2 mt-2 sm:mt-0">
            <button 
              onClick={() => setView('kaldik')}
              className={`flex items-center space-x-1 px-3 py-2 rounded-lg transition ${view === 'kaldik' ? 'bg-white text-blue-700 font-bold' : 'hover:bg-blue-600'}`}
            >
              <CalendarIcon size={18} />
              <span className="hidden sm:inline">Kaldik</span>
            </button>
            <button 
              onClick={() => setIsEditingProfile(!isEditingProfile)}
              className="flex items-center space-x-1 hover:bg-blue-600 px-3 py-2 rounded-lg transition"
            >
              <Settings size={18} />
              <span className="hidden sm:inline">Profil</span>
            </button>
            <button 
              onClick={printReport}
              className="flex items-center space-x-1 bg-green-500 hover:bg-green-600 px-4 py-2 rounded-lg transition font-medium"
            >
              <Printer size={18} />
              <span>Cetak Laporan</span>
            </button>
          </div>
        </div>
      </header>

      {/* Scanning Overlay */}
      {isScanning && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 text-center">
          <div className="bg-white rounded-3xl p-8 max-w-sm shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="relative w-20 h-20 mx-auto mb-6">
              <Loader2 className="w-full h-full text-blue-600 animate-spin" />
              <Sparkles className="absolute top-0 right-0 text-yellow-400 animate-bounce" size={24} />
            </div>
            <h2 className="text-xl font-bold text-gray-800 mb-2">Memindai Dokumen...</h2>
            <p className="text-gray-500 text-sm leading-relaxed">
              Gemini AI sedang memproses data Kalender Pendidikan Anda.
            </p>
          </div>
        </div>
      )}

      <main className="container mx-auto px-4 py-8">
        {view === 'main' ? <MainView /> : <KaldikView />}
      </main>

      <div className="fixed bottom-4 right-4 no-print flex flex-col items-end space-y-2">
        <div className="bg-white border border-gray-200 px-4 py-2 rounded-2xl shadow-xl flex items-center gap-2 text-sm">
          <AlertCircle size={16} className="text-blue-500" />
          <span>Tip: Gunakan menu "Kaldik" untuk update hari libur massal.</span>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  Plus, 
  Trash2, 
  Printer, 
  Save, 
  User, 
  FileText, 
  Settings, 
  Sparkles, 
  AlertCircle, 
  ChevronLeft, 
  ChevronRight,
  Upload,
  X,
  Loader2,
  CheckCircle2,
  Calendar as CalendarIcon,
  ArrowLeft,
  Check,
  CalendarDays
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { Profile, Activity, MonthlyLog, KaldikEvent } from './types';
import { suggestActivities, refineActivity, scanCalendar } from './services/geminiService';

const STORAGE_KEY_PROFILE = 'bck_profile';
const STORAGE_KEY_LOGS = 'bck_logs';
const STORAGE_KEY_KALDIK = 'bck_kaldik_data';

const App: React.FC = () => {
  const [view, setView] = useState<'main' | 'kaldik'>('main');
  const [profile, setProfile] = useState<Profile>({
    name: 'ALI MAKSUM, S.Pd.I',
    nuptk: '3641766668110012',
    npk: '7880990033017',
    pegId: '910',
    jabatan: "Guru Mata Pelajaran Qur'an Hadits",
    school: 'MTsS Darul Huda',
    headmasterName: 'SALAMET MOLYONO, S.Pd',
    location: 'Bondowoso',
  });

  const [currentDate, setCurrentDate] = useState(new Date());
  const [logs, setLogs] = useState<MonthlyLog[]>([]);
  const [importedKaldik, setImportedKaldik] = useState<KaldikEvent[]>([]);
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEY_PROFILE);
    if (savedProfile) setProfile(JSON.parse(savedProfile));

    const savedLogs = localStorage.getItem(STORAGE_KEY_LOGS);
    if (savedLogs) setLogs(JSON.parse(savedLogs));

    const savedKaldik = localStorage.getItem(STORAGE_KEY_KALDIK);
    if (savedKaldik) setImportedKaldik(JSON.parse(savedKaldik));
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_LOGS, JSON.stringify(logs));
  }, [logs]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_KALDIK, JSON.stringify(importedKaldik));
  }, [importedKaldik]);

  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();

  const getDaysInMonth = (month: number, year: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;
        const standardDateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${i.toString().padStart(2, '0')}`;
        const kaldikEvent = importedKaldik.find(e => e.date === standardDateStr);

        activities.push({
          id: `${currentYear}-${currentMonth}-${i}`,
          date: date.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
          description: kaldikEvent ? kaldikEvent.name : (isSunday ? 'Minggu' : ''),
          quantity: (isSunday || kaldikEvent) ? 'LU' : '',
          isHoliday: isSunday || !!kaldikEvent
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear, importedKaldik]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);

    if (logIndex === -1) {
      const newLog = { ...currentLog };
      newLog.activities = newLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs([...newLogs, newLog]);
    } else {
      newLogs[logIndex].activities = newLogs[logIndex].activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs(newLogs);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      if (file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' || file.name.endsWith('.xlsx')) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          const csvText = XLSX.utils.sheet_to_csv(workbook.Sheets[workbook.SheetNames[0]]);
          const results = await scanCalendar({ extractedText: csvText });
          if (results) setImportedKaldik(results);
          setIsScanning(false);
        };
        reader.readAsArrayBuffer(file);
      } else {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = (e.target?.result as string).split(',')[1];
          const results = await scanCalendar({ fileBase64: base64, mimeType: file.type });
