              description: isSun ? 'Minggu' : '',
              quantity: isSun ? 'LU' : '',
              isHoliday: isSun
            });
          }
          targetLog = { month: monthIndex, year: y, activities };
          newLogs.push(targetLog);
      }
      targetLog.activities = targetLog.activities.map(a => 
        (a.id === dateId) ? { ...a, description: event.name, isHoliday: true, quantity: 'LU' } : a
      );
