                  if (confirm("Hapus seluruh data (Profil, Log, Kaldik, Database)? Tindakan ini tidak bisa dibatalkan.")) {
                    localStorage.clear();
                    window.location.reload();
                  }
                }}
                className="w-full flex items-center justify-center gap-2 bg-red-600 text-white py-3 rounded-xl hover:bg-red-700 transition text-sm font-semibold"
              >
                Hapus Seluruh Data Aplikasi
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen pb-20">
      <header className="bg-blue-700 text-white shadow-lg no-print sticky top-0 z-50">
        <div className="container mx-auto px-4 py-4 flex flex-wrap items-center justify-between">
          <div className="flex items-center space-x-2 cursor-pointer" onClick={() => setView('main')}>
            <FileText size={28} />
            <h1 className="text-xl font-bold tracking-tight">BCK Smart Log</h1>
          </div>
          <div className="flex items-center space-x-2 mt-2 sm:mt-0">
            <button onClick={() => setView('kaldik')} className={`flex items-center space-x-1 px-3 py-2 rounded-lg transition ${view === 'kaldik' ? 'bg-white text-blue-700 font-bold' : 'hover:bg-blue-600'}`}><CalendarIcon size={18} /><span className="hidden sm:inline">Kaldik</span></button>
            <button onClick={() => setView('settings')} className={`flex items-center space-x-1 px-3 py-2 rounded-lg transition ${view === 'settings' ? 'bg-white text-blue-700 font-bold' : 'hover:bg-blue-600'}`}><SettingsIcon size={18} /><span className="hidden sm:inline">Pengaturan</span></button>
            <button onClick={() => setIsEditingProfile(!isEditingProfile)} className={`flex items-center space-x-1 px-3 py-2 rounded-lg transition ${isEditingProfile ? 'bg-blue-800' : 'hover:bg-blue-600'}`}><User size={18} /><span className="hidden sm:inline">Profil</span></button>
            <button onClick={printReport} className="flex items-center space-x-1 bg-green-500 hover:bg-green-600 px-4 py-2 rounded-lg transition font-medium"><Printer size={18} /><span>Cetak Laporan</span></button>
          </div>
        </div>
      </header>

      {isScanning && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100] flex items-center justify-center p-6 text-center">
          <div className="bg-white rounded-3xl p-8 max-w-sm shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="relative w-20 h-20 mx-auto mb-6"><Loader2 className="w-full h-full text-blue-600 animate-spin" /><Sparkles className="absolute top-0 right-0 text-yellow-400 animate-bounce" size={24} /></div>
            <h2 className="text-xl font-bold text-gray-800 mb-2">Memindai Dokumen...</h2>
            <p className="text-gray-500 text-sm leading-relaxed">Gemini AI sedang memproses data Kalender Pendidikan Anda.</p>
          </div>
        </div>
      )}

      <main className="container mx-auto px-4 py-8">
        {view === 'main' && <MainView />}
        {view === 'kaldik' && <KaldikView />}
        {view === 'settings' && <SettingsView />}
      </main>

      <div className="fixed bottom-4 right-4 no-print flex flex-col items-end space-y-2">
        <div className="bg-white border border-gray-200 px-4 py-2 rounded-2xl shadow-xl flex items-center gap-2 text-sm">
          <AlertCircle size={16} className="text-blue-500" />
          <span>Tip: Klik ikon database di samping kolom kegiatan untuk memilih cepat.</span>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef, memo } from 'react';
import { 
  Plus, 
  Trash2, 
  Printer, 
  Save, 
  User, 
  FileText, 
  Settings as SettingsIcon, 
  Sparkles, 
  AlertCircle, 
  ChevronLeft, 
  ChevronRight,
  Upload,
  X,
  Loader2,
  CheckCircle2,
  Calendar as CalendarIcon,
  ArrowLeft,
  Check,
  CalendarDays,
  Database,
  Trash,
  ChevronDown
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { Profile, Activity, MonthlyLog, KaldikEvent } from './types';
import { suggestActivities, refineActivity, scanCalendar } from './services/geminiService';

const STORAGE_KEY_PROFILE = 'bck_profile';
const STORAGE_KEY_LOGS = 'bck_logs';
const STORAGE_KEY_KALDIK = 'bck_kaldik_data';
const STORAGE_KEY_DB = 'bck_activity_db';

// Sub-component to isolate typing state and prevent app-wide lag
const ActivityDbInput = ({ onAdd }: { onAdd: (item: string) => void }) => {
  const [text, setText] = useState('');

  const handleAdd = () => {
    if (text.trim()) {
      onAdd(text.trim());
      setText('');
    }
  };

  return (
    <div className="flex gap-2 mb-6">
      <input 
        className="flex-1 bg-gray-50 border rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" 
        placeholder="Contoh: Mengoreksi hasil ulangan siswa..."
        value={text}
        onChange={(e) => setText(e.target.value)}
        onKeyDown={(e) => e.key === 'Enter' && handleAdd()}
      />
      <button 
        onClick={handleAdd} 
        className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition active:scale-95 flex items-center justify-center"
      >
        <Plus size={24} />
      </button>
    </div>
  );
};

const App: React.FC = () => {
  const [view, setView] = useState<'main' | 'kaldik' | 'settings'>('main');
  const [profile, setProfile] = useState<Profile>({
    name: 'ALI MAKSUM, S.Pd.I',
    nuptk: '3641766668110012',
    npk: '7880990033017',
    pegId: '910',
    jabatan: "Guru Mata Pelajaran Qur'an Hadits",
    school: 'MTsS Darul Huda',
    headmasterName: 'SALAMET MOLYONO, S.Pd',
    location: 'Bondowoso',
  });

  const [currentDate, setCurrentDate] = useState(new Date());
  const [logs, setLogs] = useState<MonthlyLog[]>([]);
  const [importedKaldik, setImportedKaldik] = useState<KaldikEvent[]>([]);
  const [activityDb, setActivityDb] = useState<string[]>([]);
  const [openDbRowId, setOpenDbRowId] = useState<string | null>(null);

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedProfile = localStorage.getItem(STORAGE_KEY_PROFILE);
    if (savedProfile) setProfile(JSON.parse(savedProfile));

    const savedLogs = localStorage.getItem(STORAGE_KEY_LOGS);
    if (savedLogs) setLogs(JSON.parse(savedLogs));

    const savedKaldik = localStorage.getItem(STORAGE_KEY_KALDIK);
    if (savedKaldik) setImportedKaldik(JSON.parse(savedKaldik));

    const savedDb = localStorage.getItem(STORAGE_KEY_DB);
    if (savedDb) setActivityDb(JSON.parse(savedDb));
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_LOGS, JSON.stringify(logs));
  }, [logs]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_KALDIK, JSON.stringify(importedKaldik));
  }, [importedKaldik]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_DB, JSON.stringify(activityDb));
  }, [activityDb]);

  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();

  const getDaysInMonth = (month: number, year: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;
        const standardDateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${i.toString().padStart(2, '0')}`;
        const kaldikEvent = importedKaldik.find(e => e.date === standardDateStr);

        activities.push({
          id: `${currentYear}-${currentMonth}-${i}`,
          date: date.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
          description: kaldikEvent ? kaldikEvent.name : (isSunday ? 'Minggu' : ''),
          quantity: (isSunday || kaldikEvent) ? 'LU' : '',
          isHoliday: isSunday || !!kaldikEvent
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear, importedKaldik]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);

    if (logIndex === -1) {
      const newLog = { ...currentLog };
      newLog.activities = newLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs([...newLogs, newLog]);
    } else {
      newLogs[logIndex].activities = newLogs[logIndex].activities.map(a => a.id === id ? { ...a, ...updates } : a);
      setLogs(newLogs);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      if (file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' || file.name.endsWith('.xlsx')) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          const csvText = XLSX.utils.sheet_to_csv(workbook.Sheets[workbook.SheetNames[0]]);
          const results = await scanCalendar({ extractedText: csvText });
          if (results) setImportedKaldik(results);
          setIsScanning(false);
        };
        reader.readAsArrayBuffer(file);
      } else {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = (e.target?.result as string).split(',')[1];
          const results = await scanCalendar({ fileBase64: base64, mimeType: file.type });
          if (results) setImportedKaldik(results);
          setIsScanning(false);
        };
        reader.readAsDataURL(file);
      }
    } catch (err) {
      console.error(err);
      alert("Gagal memproses file.");
      setIsScanning(false);
    }
  };

  const applyKaldikToLogs = () => {
    if (importedKaldik.length === 0) return;
    const newLogs = [...logs];
    importedKaldik.forEach(event => {
      const [y, m, d] = event.date.split('-').map(Number);
      const monthIndex = m - 1;
      const dateId = `${y}-${monthIndex}-${d}`;
      let targetLog = newLogs.find(l => l.month === monthIndex && l.year === y);
      if (!targetLog) {
          const daysCount = getDaysInMonth(monthIndex, y);
          const activities: Activity[] = [];
          for (let i = 1; i <= daysCount; i++) {
            const iterDate = new Date(y, monthIndex, i);
            const isSun = iterDate.getDay() === 0;
            activities.push({
              id: `${y}-${monthIndex}-${i}`,
              date: iterDate.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' }),
              description: isSun ? 'Minggu' : '',
              quantity: isSun ? 'LU' : '',
              isHoliday: isSun
            });
          }
          targetLog = { month: monthIndex, year: y, activities };
          newLogs.push(targetLog);
      }
      targetLog.activities = targetLog.activities.map(a => 
        (a.id === dateId) ? { ...a, description: event.name, isHoliday: true, quantity: 'LU' } : a
      );
    });
    setLogs(newLogs);
    alert("Data Kalender Pendidikan telah diterapkan.");
    setView('main');
  };

  const addToDb = (item: string) => {
    setActivityDb([...activityDb, item]);
  };

  const removeFromDb = (index: number) => {
    setActivityDb(activityDb.filter((_, i) => i !== index));
  };

  const handleRefine = async (id: string, text: string) => {
    if (!text) return;
    setAiLoading(true);
    const refined = await refineActivity(text);
    updateActivity(id, { description: refined });
    setAiLoading(false);
  };

  const changeMonth = (offset: number) => {
    setCurrentDate(new Date(currentYear, currentMonth + offset, 1));
  };

  const printReport = () => {
    window.print();
  };

  const MainView = () => (
    <div className="animate-in fade-in slide-in-from-left-4 duration-300">
        {isEditingProfile && (
          <div className="mb-8 bg-white p-6 rounded-2xl shadow-sm border border-gray-100 no-print">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <User className="text-blue-600" />
                Pengaturan Profil & Header
              </h2>
              <button onClick={() => setIsEditingProfile(false)} className="text-gray-400 hover:text-gray-600"><X size={20} /></button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {Object.keys(profile).map((key) => (
                <div key={key}>
                  <label className="block text-xs font-semibold text-gray-500 mb-1 capitalize">{key.replace(/([A-Z])/g, ' $1').trim()}</label>
                  <input className="w-full bg-gray-50 border rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" value={(profile as any)[key]} onChange={e => setProfile({...profile, [key as keyof Profile]: e.target.value})}/>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="mb-6 flex flex-wrap items-center justify-between gap-4 no-print">
          <div className="flex items-center bg-white border border-gray-200 rounded-2xl p-1 shadow-sm">
            <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-gray-100 rounded-xl transition"><ChevronLeft size={20} /></button>
            <div className="px-6 font-bold text-gray-700 capitalize">{currentDate.toLocaleDateString('id-ID', { month: 'long', year: 'numeric' })}</div>
            <button onClick={() => changeMonth(1)} className="p-2 hover:bg-gray-100 rounded-xl transition"><ChevronRight size={20} /></button>
          </div>

          <div className="flex gap-2">
            <button onClick={async () => { setAiLoading(true); const ideas = await suggestActivities(profile.jabatan, profile.school); if (ideas) setSuggestions(ideas); setAiLoading(false); }} disabled={aiLoading} className="flex items-center space-x-2 bg-indigo-600 text-white px-5 py-2.5 rounded-xl shadow-md hover:shadow-lg transition disabled:opacity-50">
              <Sparkles size={18} /><span>{aiLoading ? 'Berpikir...' : 'Ide AI'}</span>
            </button>
          </div>
        </div>

        {(suggestions.length > 0 || activityDb.length > 0) && (
          <div className="mb-6 p-4 bg-white border border-gray-200 rounded-2xl no-print shadow-sm animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-3">
              <span className="text-sm font-bold text-gray-600">Quick-Pick Kegiatan (Global):</span>
              <button onClick={() => setSuggestions([])} className="text-gray-400 hover:text-gray-600 text-sm"><X size={16}/></button>
            </div>
            <div className="flex flex-wrap gap-2">
              {suggestions.map((s, idx) => (
                <button key={`ai-${idx}`} onClick={() => { const empty = currentLog.activities.find(a => !a.description && !a.isHoliday); if (empty) updateActivity(empty.id, { description: s, quantity: '1 Kegiatan' }); }} className="bg-indigo-50 border border-indigo-100 px-3 py-1.5 rounded-full text-xs text-indigo-600 hover:bg-indigo-600 hover:text-white transition flex items-center gap-1">
                  <Sparkles size={10}/> {s}
                </button>
              ))}
              {activityDb.map((s, idx) => (
                <button key={`db-${idx}`} onClick={() => { const empty = currentLog.activities.find(a => !a.description && !a.isHoliday); if (empty) updateActivity(empty.id, { description: s, quantity: '1 Kegiatan' }); }} className="bg-blue-50 border border-blue-100 px-3 py-1.5 rounded-full text-xs text-blue-600 hover:bg-blue-600 hover:text-white transition flex items-center gap-1">
                  <Database size={10}/> {s}
                </button>
              ))}
            </div>
          </div>
        )}

        <div id="print-area" className="bg-white shadow-2xl rounded-sm p-4 sm:p-10 border border-gray-200 overflow-visible min-w-full">
          <div className="mb-6 space-y-1">
            <div className="flex"><div className="w-40 font-bold text-sm">NAMA</div><div className="font-bold text-sm">: {profile.name}</div></div>
            <div className="flex"><div className="w-40 font-bold text-sm">NUPTK/NPK/PEG.ID</div><div className="font-bold text-sm">: {profile.nuptk} / {profile.npk} / {profile.pegId}</div></div>
            <div className="flex"><div className="w-40 font-bold text-sm">JABATAN</div><div className="font-bold text-sm">: {profile.jabatan}</div></div>
            <div className="flex"><div className="w-40 font-bold text-sm">RA/MADRASAH</div><div className="font-bold text-sm">: {profile.school}</div></div>
          </div>

          <table className="w-full border-collapse border-2 border-black text-xs relative">
            <thead className="bg-yellow-400">
              <tr>
                <th className="border-2 border-black p-1 w-[40px] text-center">NO</th>
                <th className="border-2 border-black p-1 w-[160px] text-center">TANGGAL KEGIATAN</th>
                <th className="border-2 border-black p-1 text-center">KEGIATAN HARIAN</th>
                <th className="border-2 border-black p-1 w-[100px] text-center">KUANTITAS</th>
              </tr>
            </thead>
            <tbody>
              {currentLog.activities.map((act, idx) => (
                <tr key={act.id} className={`${act.isHoliday ? 'bg-gray-200' : ''}`}>
                  <td className="border-2 border-black p-1 text-center">{idx + 1}</td>
                  <td className="border-2 border-black p-1 text-center">{act.date}</td>
                  <td className="border-2 border-black p-0 group relative align-middle">
                    <div className="flex items-center justify-center min-h-[28px]">
                      <textarea 
                        className="w-full p-1 bg-transparent resize-none outline-none border-none overflow-hidden block text-center"
                        rows={1}
                        value={act.description}
                        onChange={e => updateActivity(act.id, { description: e.target.value })}
                        style={{ height: 'auto', minHeight: '20px' }}
                      />

                      {/* Interactive Icons per row */}
                      {!act.isHoliday && (
                        <div className="absolute right-1 top-1/2 -translate-y-1/2 flex gap-1 opacity-0 group-hover:opacity-100 transition no-print z-10">
                          <button 
                            onClick={() => setOpenDbRowId(openDbRowId === act.id ? null : act.id)}
                            className={`p-1 bg-white rounded-md border shadow-sm ${openDbRowId === act.id ? 'text-blue-600 bg-blue-50 border-blue-200' : 'text-blue-500'} hover:bg-blue-50`}
                            title="Pilih dari Database"
                          >
                            <Database size={12} />
                          </button>
                          {act.description && (
                            <button 
                              onClick={() => handleRefine(act.id, act.description)} 
                              className="p-1 bg-white rounded-md border shadow-sm text-indigo-500 hover:bg-indigo-50"
                              title="Perbaiki dengan AI"
                            >
                              <Sparkles size={12} />
                            </button>
                          )}
                        </div>
                      )}

                      {/* Dropdown Menu for DB Selection */}
                      {openDbRowId === act.id && (
                        <div className="absolute z-[100] right-0 top-full mt-1 w-72 bg-white border border-gray-200 rounded-xl shadow-2xl p-2 no-print animate-in fade-in zoom-in-95 duration-200 max-h-60 overflow-y-auto custom-scrollbar text-xs">
                          <div className="flex items-center justify-between px-2 py-1 mb-1 border-b border-gray-100">
                            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">Pilih Kegiatan Database</span>
                            <button onClick={() => setOpenDbRowId(null)} className="text-gray-400 hover:text-gray-600"><X size={12}/></button>
                          </div>
                          {activityDb.length === 0 ? (
                            <div className="p-4 text-center">
                              <p className="text-[10px] text-gray-400 italic">Database kosong.</p>
                              <button 
                                onClick={() => setView('settings')}
                                className="text-[10px] text-blue-600 font-bold hover:underline mt-1"
                              >
                                Isi di Pengaturan
                              </button>
                            </div>
                          ) : (
                            <div className="space-y-1">
                              {activityDb.map((item, i) => (
                                <button 
                                  key={i}
                                  onClick={() => {
                                    updateActivity(act.id, { description: item, quantity: '1 Kegiatan' });
                                    setOpenDbRowId(null);
                                  }}
                                  className="w-full text-left p-2 text-[11px] text-gray-700 hover:bg-blue-50 rounded-lg transition-colors border border-transparent hover:border-blue-100 whitespace-normal leading-relaxed"
                                >
                                  {item}
                                </button>
                              ))}
                            </div>
                          )}
                        </div>
