            <FileText size={28} />
            <div className="flex flex-col">
              <h1 className="text-xl font-bold tracking-tight">BCK Smart Log</h1>
              {isSuperAdmin && (
                <div className="flex items-center gap-1 text-[8px] bg-cyan-400 text-blue-900 font-black px-1 rounded animate-pulse w-fit">
                  <ShieldAlert size={8} /> <span>SUPER ADMIN</span>
                </div>
              )}
            </div>
          </div>
          <div className="flex items-center space-x-2 mt-2 sm:mt-0">
            <button onClick={() => setView('kaldik')} className={`flex items-center space-x-1 px-3 py-2 rounded-lg transition ${view === 'kaldik' ? 'bg-white text-blue-700 font-bold' : 'hover:bg-blue-600'}`}><CalendarIcon size={18} /><span className="hidden sm:inline">Kaldik</span></button>
            <button onClick={() => setView('settings')} className={`flex items-center space-x-1 px-3 py-2 rounded-lg transition ${view === 'settings' ? 'bg-white text-blue-700 font-bold' : 'hover:bg-blue-600'}`}><SettingsIcon size={18} /><span className="hidden sm:inline">Settings</span></button>
            <button onClick={() => setIsEditingProfile(!isEditingProfile)} className={`flex items-center space-x-1 px-3 py-2 rounded-lg transition ${isEditingProfile ? 'bg-blue-800' : 'hover:bg-blue-600'}`}><User size={18} /><span className="hidden sm:inline">Profil</span></button>
            <button onClick={() => window.print()} className="flex items-center space-x-1 bg-green-500 hover:bg-green-600 px-4 py-2 rounded-lg transition font-medium"><Printer size={18} /><span>Cetak</span></button>
          </div>
        </div>
      </header>
      {isScanning && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md z-[100] flex items-center justify-center text-center">
          <div className="bg-white rounded-3xl p-8 max-w-sm shadow-2xl">
            <Loader2 className="w-16 h-16 text-blue-600 animate-spin mx-auto mb-6" />
            <h2 className="text-xl font-bold text-gray-800 mb-2">Memindai Dokumen...</h2>
          </div>
        </div>
      )}
      <main className="container mx-auto px-4 py-8">
        {view === 'main' && <MainView />}
        {view === 'kaldik' && <KaldikView />}
        {view === 'settings' && <SettingsView />}
      </main>
    </div>
  );
};

export default App;

payload.text:
Kesalahan tersebut terjadi karena tabel `monthly_logs` (atau `kaldik_data`) di database Supabase Anda belum memiliki kolom bernama `user_id`.

Untuk memperbaikinya, Anda tidak perlu mengisi formulir di UI satu per satu. Cara terbaik adalah menjalankan perintah SQL berikut di **SQL Editor** Supabase Anda. Ini akan membuat tabel dengan struktur yang benar dan mengaktifkan kebijakan keamanan (RLS) secara otomatis.

### 🛠️ Jalankan Kode SQL Ini di Supabase SQL Editor:

```sql
-- 1. Tabel Profiles (1 baris per user)
create table if not exists public.profiles (
  id uuid references auth.users not null primary key,
  data jsonb,
  updated_at timestamp with time zone default now()
);

-- 2. Tabel Monthly Logs (1 baris per bulan per user)
create table if not exists public.monthly_logs (
  user_id uuid references auth.users not null,
  month int not null,
  year int not null,
  activities jsonb,
  updated_at timestamp with time zone default now(),
  primary key (user_id, month, year)
);

-- 3. Tabel Activity DB (1 baris per user)
create table if not exists public.activity_db (
  id uuid references auth.users not null primary key,
  items jsonb,
  updated_at timestamp with time zone default now()
);

-- 4. Tabel Kaldik Data (1 baris per user)
create table if not exists public.kaldik_data (
  user_id uuid references auth.users not null primary key,
  events jsonb,
  updated_at timestamp with time zone default now()
);

-- Aktifkan Row Level Security (RLS)
alter table public.profiles enable row level security;
alter table public.monthly_logs enable row level security;
alter table public.activity_db enable row level security;
alter table public.kaldik_data enable row level security;

-- Buat Kebijakan (Policies) agar user hanya bisa akses data sendiri
create policy "Manage own profile" on public.profiles for all using (auth.uid() = id);
create policy "Manage own logs" on public.monthly_logs for all using (auth.uid() = user_id);
create policy "Manage own activity db" on public.activity_db for all using (auth.uid() = id);
create policy "Manage own kaldik" on public.kaldik_data for all using (auth.uid() = user_id);
```

Saya juga telah memperbarui kode aplikasi agar lebih stabil saat mengambil data yang belum ada di database menggunakan `.maybeSingle()`.

