              type="submit" 
              disabled={loading}
              className="w-full neon-btn bg-transparent border border-cyan-500 text-cyan-400 py-4 rounded-xl font-bold uppercase tracking-[0.5em] text-xs flex items-center justify-center gap-3"
            >
              {loading ? <Loader2 className="animate-spin" size={18} /> : (
                <>
                  {isRegister ? <UserPlus size={18} /> : <Cpu size={18} />}
                  <span>{isRegister ? 'Register' : 'Execute Sync'}</span>
                </>
              )}
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-cyan-500/20 text-center">
             <button 
              onClick={() => setIsRegister(!isRegister)}
              className="text-[10px] text-cyan-400/60 hover:text-cyan-400 uppercase tracking-widest transition-colors underline decoration-cyan-500/30 underline-offset-4"
            >
              {isRegister ? 'Already have access? Login' : 'New Protocol? Register Access'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

const ActivityDbInput = ({ onAdd }: { onAdd: (item: string) => void }) => {
  const [text, setText] = useState('');
  const handleAdd = () => {
    if (text.trim()) {
      onAdd(text.trim());
      setText('');
    }
  };
  return (
    <div className="flex gap-2 mb-6">
      <input className="flex-1 bg-gray-50 border rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" placeholder="Contoh: Mengoreksi hasil ulangan siswa..." value={text} onChange={(e) => setText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAdd()} />
      <button onClick={handleAdd} className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition active:scale-95 flex items-center justify-center"><Plus size={24} /></button>
    </div>
  );
};

const App: React.FC = () => {
  const [sessionUser, setSessionUser] = useState<SupabaseUser | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);
  const [isCloudDataReady, setIsCloudDataReady] = useState(false);
  const [view, setView] = useState<'main' | 'kaldik' | 'settings'>('main');

  const [profile, setProfile] = useState<Profile>({
    name: 'ALI MAKSUM, S.Pd.I',
    nuptk: '3641766668110012',
    npk: '7880990033017',
    pegId: '910',
    jabatan: "Guru Mata Pelajaran Qur'an Hadits",
    school: 'MTsS Darul Huda',
    headmasterName: 'SALAMET MOLYONO, S.Pd',
    location: 'Bondowoso',
  });

  const [currentDate, setCurrentDate] = useState(new Date());
  const [logs, setLogs] = useState<MonthlyLog[]>([]);
  const [importedKaldik, setImportedKaldik] = useState<KaldikEvent[]>([]);
  const [activityDb, setActivityDb] = useState<string[]>([]);
  const [openDbRowId, setOpenDbRowId] = useState<string | null>(null);
  const [cloudStatus, setCloudStatus] = useState<'idle' | 'syncing' | 'error'>('idle');

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isSuperAdmin = sessionUser?.email === SUPER_ADMIN_EMAIL;

  // Authentication State Listener
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSessionUser(session?.user ?? null);
      setIsInitializing(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSessionUser(session?.user ?? null);
      if (!session) {
        setIsCloudDataReady(false);
        setLogs([]);
        setImportedKaldik([]);
        setActivityDb([]);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  // Effect to load local data initially
  useEffect(() => {
    if (!isInitializing) {
      const savedProfile = localStorage.getItem(STORAGE_KEY_PROFILE);
      if (savedProfile) setProfile(JSON.parse(savedProfile));

      const savedLogs = localStorage.getItem(STORAGE_KEY_LOGS);
      if (savedLogs) setLogs(JSON.parse(savedLogs));

      const savedKaldik = localStorage.getItem(STORAGE_KEY_KALDIK);
      if (savedKaldik) setImportedKaldik(JSON.parse(savedKaldik));

      const savedDb = localStorage.getItem(STORAGE_KEY_DB);
      if (savedDb) setActivityDb(JSON.parse(savedDb));

      if (sessionUser) {
        loadFromCloud();
      }
    }
  }, [sessionUser, isInitializing]);

  // Unified Syncing - ONLY RUNS AFTER CLOUD DATA IS READY
  useEffect(() => {
    if (sessionUser && isCloudDataReady) {
      localStorage.setItem(STORAGE_KEY_KALDIK, JSON.stringify(importedKaldik));
      syncToCloud('kaldik_data', { user_id: sessionUser.id, events: importedKaldik });
    }
  }, [importedKaldik, sessionUser, isCloudDataReady]);

  useEffect(() => {
    if (sessionUser && isCloudDataReady) {
      localStorage.setItem(STORAGE_KEY_DB, JSON.stringify(activityDb));
      syncToCloud('activity_db', { id: sessionUser.id, items: activityDb });
    }
  }, [activityDb, sessionUser, isCloudDataReady]);

  useEffect(() => {
    if (sessionUser && isCloudDataReady) {
      localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
      syncToCloud('profiles', { id: sessionUser.id, data: profile });
    }
  }, [profile, sessionUser, isCloudDataReady]);

  const loadFromCloud = async () => {
    if (!sessionUser) return;
    setCloudStatus('syncing');
    try {
      // Fetch data with maybeSingle to avoid errors
      const { data: profileData } = await supabase.from('profiles').select('*').eq('id', sessionUser.id).maybeSingle();
      if (profileData) {
        setProfile(profileData.data);
        localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profileData.data));
      }

      const { data: logsData } = await supabase.from('monthly_logs').select('*').eq('user_id', sessionUser.id);
      if (logsData && logsData.length > 0) {
        const formattedLogs = logsData.map(l => ({ month: l.month, year: l.year, activities: l.activities }));
        setLogs(formattedLogs);
        localStorage.setItem(STORAGE_KEY_LOGS, JSON.stringify(formattedLogs));
      }

      const { data: dbData } = await supabase.from('activity_db').select('*').eq('id', sessionUser.id).maybeSingle();
      if (dbData) {
        setActivityDb(dbData.items);
        localStorage.setItem(STORAGE_KEY_DB, JSON.stringify(dbData.items));
      }

      const { data: kaldikData } = await supabase.from('kaldik_data').select('*').eq('user_id', sessionUser.id).maybeSingle();
      if (kaldikData) {
        setImportedKaldik(kaldikData.events);
        localStorage.setItem(STORAGE_KEY_KALDIK, JSON.stringify(kaldikData.events));
      }

      // CRITICAL: Mark cloud as ready to allow outgoing syncs
      setIsCloudDataReady(true);
      setCloudStatus('idle');
    } catch (e) {
      console.error("Cloud fetch failed", e);
      setCloudStatus('error');
    }
  };

  const syncToCloud = async (table: string, payload: any) => {
    // SECURITY: Never sync if cloud data isn't verified ready
    if (!sessionUser || !isCloudDataReady) return;

    setCloudStatus('syncing');
    try {
      const { error } = await supabase.from(table).upsert({ ...payload, updated_at: new Date() });
      if (error) throw error;
      setCloudStatus('idle');
    } catch (e) {
      console.error(`Sync failed for ${table}:`, e);
      setCloudStatus('error');
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    localStorage.clear();
    setIsCloudDataReady(false);
    window.location.reload();
  };

  // Activity Logic
  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();
  const getDaysInMonth = (month: number, year: number) => new Date(year, month + 1, 0).getDate();

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;
        const standardDateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${i.toString().padStart(2, '0')}`;
        const kaldikEvent = importedKaldik.find(e => e.date === standardDateStr);
        activities.push({
          id: `${currentYear}-${currentMonth}-${i}`,
          date: date.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }),
          description: kaldikEvent ? kaldikEvent.name : (isSunday ? 'Minggu' : ''),
          quantity: (isSunday || kaldikEvent) ? 'LU' : '',
          isHoliday: isSunday || !!kaldikEvent
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear, importedKaldik]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    if (!sessionUser) return;
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);
    let updatedLog: MonthlyLog;

    if (logIndex === -1) {
      updatedLog = { ...currentLog };
      updatedLog.activities = updatedLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      newLogs.push(updatedLog);
      setLogs(newLogs);
    } else {
      updatedLog = { ...newLogs[logIndex] };
      updatedLog.activities = updatedLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      newLogs[logIndex] = updatedLog;
      setLogs(newLogs);
    }

    if (isCloudDataReady) {
      syncToCloud('monthly_logs', { user_id: sessionUser.id, month: currentMonth, year: currentYear, activities: updatedLog.activities });
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      if (file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' || file.name.endsWith('.xlsx')) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          const csvText = XLSX.utils.sheet_to_csv(workbook.Sheets[workbook.SheetNames[0]]);
          const results = await scanCalendar({ extractedText: csvText });
          if (results) setImportedKaldik(results);
          setIsScanning(false);
        };
        reader.readAsArrayBuffer(file);
      } else {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = (e.target?.result as string).split(',')[1];
          const results = await scanCalendar({ fileBase64: base64, mimeType: file.type });
          if (results) setImportedKaldik(results);
          setIsScanning(false);
        };
        reader.readAsDataURL(file);
      }
    } catch (err) {
      setIsScanning(false);
    }
  };

  const applyKaldikToLogs = () => {
    if (importedKaldik.length === 0) return;
    const newLogs = [...logs];
    importedKaldik.forEach(event => {
      const [y, m, d] = event.date.split('-').map(Number);
      const monthIndex = m - 1;
      const dateId = `${y}-${monthIndex}-${d}`;
      let targetLog = newLogs.find(l => l.month === monthIndex && l.year === y);
      if (!targetLog) {
          const daysCount = getDaysInMonth(monthIndex, y);
          const activities: Activity[] = [];
          for (let i = 1; i <= daysCount; i++) {
            const iterDate = new Date(y, monthIndex, i);
            const isSun = iterDate.getDay() === 0;
            activities.push({
              id: `${y}-${monthIndex}-${i}`,
              date: iterDate.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }),
              description: isSun ? 'Minggu' : '',
              quantity: isSun ? 'LU' : '',
              isHoliday: isSun
            });
          }
          targetLog = { month: monthIndex, year: y, activities };
          newLogs.push(targetLog);
      }
      targetLog.activities = targetLog.activities.map(a => (a.id === dateId) ? { ...a, description: event.name, isHoliday: true, quantity: 'LU' } : a);
    });
    setLogs(newLogs);
    setView('main');
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen cyber-bg flex items-center justify-center">
        <Loader2 className="animate-spin text-cyan-400" size={48} />
      </div>
    );
  }

  if (!sessionUser) {
    return <LoginView />;
  }

  const MainView = () => (
    <div className="animate-in fade-in slide-in-from-left-4 duration-300">
        {!isCloudDataReady && (
          <div className="mb-4 bg-yellow-500/10 border border-yellow-500/30 p-4 rounded-2xl flex items-center gap-4 text-yellow-600 animate-pulse shadow-sm">
            <RefreshCw className="animate-spin" size={24} />
            <div>
              <p className="font-bold text-sm">MENYINGKRONKAN DATABASE CLOUD...</p>
              <p className="text-[10px] opacity-70">Jangan tutup aplikasi hingga proses verifikasi selesai.</p>
            </div>
          </div>
        )}
        {isEditingProfile && (
          <div className="mb-8 bg-white p-6 rounded-2xl shadow-sm border border-gray-100 no-print">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <User className="text-blue-600" /> Pengaturan Profil
              </h2>
              <button onClick={() => setIsEditingProfile(false)} className="text-gray-400 hover:text-gray-600"><X size={20} /></button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {Object.keys(profile).map((key) => (
                <div key={key}>
                  <label className="block text-xs font-semibold text-gray-500 mb-1 capitalize">{key.replace(/([A-Z])/g, ' $1').trim()}</label>
                  <input className="w-full bg-gray-50 border rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" value={(profile as any)[key]} onChange={e => setProfile({...profile, [key as keyof Profile]: e.target.value})}/>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="mb-6 flex flex-wrap items-center justify-between gap-4 no-print">
          <div className="flex items-center bg-white border border-gray-200 rounded-2xl p-1 shadow-sm">
            <button onClick={() => setCurrentDate(new Date(currentYear, currentMonth - 1, 1))} className="p-2 hover:bg-gray-100 rounded-xl transition"><ChevronLeft size={20} /></button>
            <div className="px-6 font-bold text-gray-700 capitalize">{currentDate.toLocaleDateString('id-ID', { month: 'long', year: 'numeric' })}</div>
            <button onClick={() => setCurrentDate(new Date(currentYear, currentMonth + 1, 1))} className="p-2 hover:bg-gray-100 rounded-xl transition"><ChevronRight size={20} /></button>
          </div>
          <div className="flex gap-2">
            <button onClick={async () => { setAiLoading(true); const ideas = await suggestActivities(profile.jabatan, profile.school); if (ideas) setSuggestions(ideas); setAiLoading(false); }} disabled={aiLoading} className="flex items-center space-x-2 bg-indigo-600 text-white px-5 py-2.5 rounded-xl shadow-md hover:shadow-lg transition disabled:opacity-50">
              <Sparkles size={18} /><span>{aiLoading ? 'Berpikir...' : 'Ide AI'}</span>
            </button>
          </div>
        </div>

        {(suggestions.length > 0 || activityDb.length > 0) && (
          <div className="mb-6 p-4 bg-white border border-gray-200 rounded-2xl no-print shadow-sm animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-3"><span className="text-sm font-bold text-gray-600">Quick-Pick:</span><button onClick={() => setSuggestions([])} className="text-gray-400 hover:text-gray-600 text-sm"><X size={16}/></button></div>
            <div className="flex flex-wrap gap-2">
              {suggestions.map((s, idx) => (
                <button key={`ai-${idx}`} onClick={() => { const empty = currentLog.activities.find(a => !a.description && !a.isHoliday); if (empty) updateActivity(empty.id, { description: s, quantity: '1 Kegiatan' }); }} className="bg-indigo-50 border border-indigo-100 px-3 py-1.5 rounded-full text-xs text-indigo-600 hover:bg-indigo-600 hover:text-white transition flex items-center gap-1"><Sparkles size={10}/> {s}</button>
              ))}
              {activityDb.map((s, idx) => (
                <button key={`db-${idx}`} onClick={() => { const empty = currentLog.activities.find(a => !a.description && !a.isHoliday); if (empty) updateActivity(empty.id, { description: s, quantity: '1 Kegiatan' }); }} className="bg-blue-50 border border-blue-100 px-3 py-1.5 rounded-full text-xs text-blue-600 hover:bg-blue-600 hover:text-white transition flex items-center gap-1"><Database size={10}/> {s}</button>
              ))}
            </div>
          </div>
        )}

        <div id="print-area" className="bg-white shadow-2xl rounded-sm p-4 sm:p-10 border border-gray-200 overflow-visible min-w-full">
          <div className="mb-6 space-y-1">
            <div className="flex"><div className="w-40 font-bold text-sm">NAMA</div><div className="font-bold text-sm">: {profile.name}</div></div>
            <div className="flex"><div className="w-40 font-bold text-sm">NUPTK/NPK/PEG.ID</div><div className="font-bold text-sm">: {profile.nuptk} / {profile.npk} / {profile.pegId}</div></div>
            <div className="flex"><div className="w-40 font-bold text-sm">JABATAN</div><div className="font-bold text-sm">: {profile.jabatan}</div></div>
            <div className="flex"><div className="w-40 font-bold text-sm">RA/MADRASAH</div><div className="font-bold text-sm">: {profile.school}</div></div>
          </div>

          <table className="w-full border-collapse border-2 border-black text-xs relative">
            <thead className="bg-yellow-400">
              <tr>
                <th className="border-2 border-black p-1 w-[40px] text-center">NO</th>
                <th className="border-2 border-black p-1 w-[180px] text-center">TANGGAL KEGIATAN</th>
                <th className="border-2 border-black p-1 text-center">KEGIATAN HARIAN</th>
                <th className="border-2 border-black p-1 w-[100px] text-center">KUANTITAS</th>
              </tr>
            </thead>
            <tbody>
              {currentLog.activities.map((act, idx) => (
                <tr key={act.id} className={`${act.isHoliday ? 'bg-gray-200' : ''}`}>
                  <td className="border-2 border-black p-1 text-center">{idx + 1}</td>
                  <td className="border-2 border-black p-1 text-center leading-tight">{act.date}</td>
                  <td className="border-2 border-black p-0 group relative align-middle">
                    <div className="flex items-center justify-center min-h-[28px]">
                      <textarea className="w-full p-1 bg-transparent resize-none outline-none border-none overflow-hidden block text-center" rows={1} value={act.description} onChange={e => updateActivity(act.id, { description: e.target.value })} style={{ height: 'auto', minHeight: '20px' }} />
                      {!act.isHoliday && (
                        <div className="absolute right-1 top-1/2 -translate-y-1/2 flex gap-1 opacity-0 group-hover:opacity-100 transition no-print z-10">
                          <button onClick={() => setOpenDbRowId(openDbRowId === act.id ? null : act.id)} className={`p-1 bg-white rounded-md border shadow-sm ${openDbRowId === act.id ? 'text-blue-600 bg-blue-50 border-blue-200' : 'text-blue-500'} hover:bg-blue-50`}><Database size={12} /></button>
                          {act.description && <button onClick={() => { setAiLoading(true); refineActivity(act.description).then(res => { updateActivity(act.id, { description: res }); setAiLoading(false); }); }} className="p-1 bg-white rounded-md border shadow-sm text-indigo-500 hover:bg-indigo-50"><Sparkles size={12} /></button>}
                        </div>
                      )}
                      {openDbRowId === act.id && (
                        <div className="absolute z-[100] right-0 top-full mt-1 w-72 bg-white border border-gray-200 rounded-xl shadow-2xl p-2 no-print animate-in fade-in zoom-in-95 duration-200 max-h-60 overflow-y-auto custom-scrollbar text-xs">
                          {activityDb.map((item, i) => (
                            <button key={i} onClick={() => { updateActivity(act.id, { description: item, quantity: '1 Kegiatan' }); setOpenDbRowId(null); }} className="w-full text-left p-2 hover:bg-blue-50 rounded-lg">{item}</button>
                          ))}
                        </div>
                      )}
                    </div>
                  </td>
                  <td className="border-2 border-black p-0 text-center align-middle"><input className="w-full p-1 bg-transparent text-center border-none outline-none" value={act.quantity} onChange={e => updateActivity(act.id, { quantity: e.target.value })}/></td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="mt-12 grid grid-cols-2 gap-20">
            <div className="text-center"><p className="mb-20">Mengetahui<br/>Kepala Madrasah</p><p className="font-bold underline uppercase">{profile.headmasterName}</p></div>
            <div className="text-center"><p className="mb-20">{profile.location}, {currentLog.activities[currentLog.activities.length - 1].date}<br/>Guru Kelas/Mapel</p><p className="font-bold underline uppercase">{profile.name}</p></div>
          </div>
        </div>
    </div>
  );

  const KaldikView = () => (
    <div className="animate-in fade-in slide-in-from-right-4 duration-300">
      <div className="flex items-center justify-between mb-8">
        <button onClick={() => setView('main')} className="flex items-center gap-2 text-gray-500 hover:text-blue-600 font-medium"><ArrowLeft size={20} /><span>Kembali</span></button>
        <h2 className="text-2xl font-bold text-gray-800">Manajemen Kaldik</h2>
      </div>
      {!isCloudDataReady && (
        <div className="mb-6 bg-blue-50 p-4 rounded-2xl flex items-center gap-3 text-blue-700">
          <Loader2 className="animate-spin" size={20} />
          <span>Memuat data Kaldik dari Cloud...</span>
        </div>
      )}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
            <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2"><Upload size={18} className="text-blue-600" />Import</h3>
            <input type="file" ref={fileInputRef} className="hidden" accept=".pdf,.xlsx,.jpg,.png" onChange={handleFileUpload}/>
            <button onClick={() => fileInputRef.current?.click()} className="w-full bg-blue-600 hover:bg-blue-700 text-white py-4 rounded-2xl transition font-bold"><Upload size={20} /><span>Pilih Dokumen</span></button>
          </div>
          {importedKaldik.length > 0 && <button onClick={applyKaldikToLogs} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold">Terapkan ({importedKaldik.length})</button>}
        </div>
        <div className="lg:col-span-2">
          <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden max-h-[600px] overflow-y-auto">
            <div className="divide-y divide-gray-50">{importedKaldik.map((event, idx) => (
              <div key={idx} className="p-4 flex items-center justify-between hover:bg-gray-50">
                <div className="flex items-center gap-4"><div className="bg-blue-50 text-blue-600 p-2 rounded-lg font-bold text-xs w-24 text-center">{new Date(event.date).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}</div><span className="text-sm font-semibold text-gray-700">{event.name}</span></div>
                <button onClick={() => setImportedKaldik(importedKaldik.filter((_, i) => i !== idx))} className="text-gray-300 hover:text-red-500"><Trash2 size={16} /></button>
              </div>
            ))}</div>
          </div>
        </div>
      </div>
    </div>
  );

  const SettingsView = () => (
