const SQL_FIX_SCRIPT = `-- SALIN DAN JALANKAN DI SQL EDITOR SUPABASE:

-- 1. Pastikan tabel monthly_logs memiliki primary key yang benar
DO $$ 
BEGIN
    IF EXISTS (SELECT 1 FROM pg_tables WHERE tablename = 'monthly_logs') THEN
        -- Coba hapus constraint lama jika ada (opsional, tergantung struktur lama)
        -- ALTER TABLE public.monthly_logs DROP CONSTRAINT IF EXISTS monthly_logs_pkey;
        -- Pastikan kolom ada
        ALTER TABLE public.monthly_logs ADD COLUMN IF NOT EXISTS user_id uuid REFERENCES auth.users(id);
        ALTER TABLE public.monthly_logs ADD COLUMN IF NOT EXISTS month int;
        ALTER TABLE public.monthly_logs ADD COLUMN IF NOT EXISTS year int;
        ALTER TABLE public.monthly_logs ADD COLUMN IF NOT EXISTS activities jsonb DEFAULT '[]'::jsonb;
        ALTER TABLE public.monthly_logs ADD COLUMN IF NOT EXISTS updated_at timestamptz DEFAULT now();
    ELSE
        CREATE TABLE public.monthly_logs (
            user_id uuid REFERENCES auth.users(id), 
            month int, 
            year int, 
            activities jsonb DEFAULT '[]'::jsonb,
            updated_at timestamptz DEFAULT now(),
            PRIMARY KEY (user_id, month, year)
        );
    END IF;
END $$;

-- 2. Tambahkan kolom ke tabel lain
ALTER TABLE IF EXISTS public.profiles ADD COLUMN IF NOT EXISTS data jsonb DEFAULT '{}'::jsonb;
ALTER TABLE IF EXISTS public.profiles ADD COLUMN IF NOT EXISTS updated_at timestamptz DEFAULT now();

ALTER TABLE IF EXISTS public.activity_db ADD COLUMN IF NOT EXISTS items jsonb DEFAULT '[]'::jsonb;
ALTER TABLE IF EXISTS public.activity_db ADD COLUMN IF NOT EXISTS updated_at timestamptz DEFAULT now();

ALTER TABLE IF EXISTS public.kaldik_data ADD COLUMN IF NOT EXISTS events jsonb DEFAULT '[]'::jsonb;
ALTER TABLE IF EXISTS public.kaldik_data ADD COLUMN IF NOT EXISTS updated_at timestamptz DEFAULT now();

-- 3. Pastikan tabel dasar ada
CREATE TABLE IF NOT EXISTS public.profiles (id uuid PRIMARY KEY REFERENCES auth.users(id));
CREATE TABLE IF NOT EXISTS public.activity_db (id uuid PRIMARY KEY REFERENCES auth.users(id));
CREATE TABLE IF NOT EXISTS public.kaldik_data (user_id uuid PRIMARY KEY REFERENCES auth.users(id));`;

