  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();
  const getDaysInMonth = (month: number, year: number) => new Date(year, month + 1, 0).getDate();

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;
        const standardDateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${i.toString().padStart(2, '0')}`;
        const kaldikEvent = importedKaldik.find(e => e.date === standardDateStr);
        activities.push({
          id: `${currentYear}-${currentMonth}-${i}`,
          date: date.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }),
          description: kaldikEvent ? kaldikEvent.name : (isSunday ? 'Minggu' : ''),
          quantity: (isSunday || kaldikEvent) ? 'LU' : '',
          isHoliday: isSunday || !!kaldikEvent
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear, importedKaldik]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    if (!sessionUser) return;
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);
    let updatedLog: MonthlyLog;
    if (logIndex === -1) {
      updatedLog = { ...currentLog };
      updatedLog.activities = updatedLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      newLogs.push(updatedLog);
      setLogs(newLogs);
    } else {
      updatedLog = { ...newLogs[logIndex] };
      updatedLog.activities = updatedLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      newLogs[logIndex] = updatedLog;
      setLogs(newLogs);
    }
    if (isCloudDataReady) syncToCloud('monthly_logs', { user_id: sessionUser.id, month: currentMonth, year: currentYear, activities: updatedLog.activities }, 'user_id,month,year');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      if (file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' || file.name.endsWith('.xlsx')) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          const csvText = XLSX.utils.sheet_to_csv(workbook.Sheets[workbook.SheetNames[0]]);
          const results = await scanCalendar({ extractedText: csvText });
          if (results) {
            setImportedKaldik(results);
            showToast("Kaldik berhasil diimpor", "success");
          }
          setIsScanning(false);
        };
        reader.readAsArrayBuffer(file);
      } else {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = (e.target?.result as string).split(',')[1];
          const results = await scanCalendar({ fileBase64: base64, mimeType: file.type });
          if (results) {
            setImportedKaldik(results);
            showToast("Kaldik berhasil diproses", "success");
          }
          setIsScanning(false);
        };
        reader.readAsDataURL(file);
      }
    } catch (err) { 
      setIsScanning(false); 
      showToast("Gagal memproses file", "error");
    }
  };

  const applyKaldikToLogs = () => {
    if (importedKaldik.length === 0) return;
    const newLogs = [...logs];
    importedKaldik.forEach(event => {
      const [y, m, d] = event.date.split('-').map(Number);
      const monthIndex = m - 1;
      const dateId = `${y}-${monthIndex}-${d}`;
      let targetLog = newLogs.find(l => l.month === monthIndex && l.year === y);
      if (!targetLog) {
          const daysCount = getDaysInMonth(monthIndex, y);
          const activities: Activity[] = [];
          for (let i = 1; i <= daysCount; i++) {
            const iterDate = new Date(y, monthIndex, i);
            const isSun = iterDate.getDay() === 0;
            activities.push({
              id: `${y}-${monthIndex}-${i}`, date: iterDate.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }), description: isSun ? 'Minggu' : '', quantity: isSun ? 'LU' : '', isHoliday: isSun
            });
          }
          targetLog = { month: monthIndex, year: y, activities };
          newLogs.push(targetLog);
      }
      targetLog.activities = targetLog.activities.map(a => (a.id === dateId) ? { ...a, description: event.name, isHoliday: true, quantity: 'LU' } : a);
    });
    setLogs(newLogs);
    setView('main');
    showToast("Kaldik diterapkan ke log harian", "success");
  };

  const copySql = () => {
    navigator.clipboard.writeText(SQL_FIX_SCRIPT);
    alert("Script SQL perbaikan berhasil disalin! Silakan jalankan di Supabase SQL Editor.");
  };

  if (isInitializing) {
    return <div className="min-h-screen cyber-bg flex items-center justify-center"><Loader2 className="animate-spin text-cyan-400" size={48} /></div>;
  }
  if (!sessionUser) return <LoginView />;

  const MainView = () => (
    <div className="animate-in fade-in slide-in-from-left-4 duration-300">
        {!isCloudDataReady && (
          <div className="mb-4 bg-yellow-500/10 border border-yellow-500/30 p-4 rounded-2xl flex items-center justify-between gap-4 text-yellow-600 shadow-sm">
            <div className="flex items-center gap-4">
              <RefreshCw className="animate-spin" size={24} />
              <div>
                <p className="font-bold text-sm">MENYINGKRONKAN DATABASE CLOUD...</p>
                <p className="text-[10px] opacity-70">Jangan tutup aplikasi hingga proses verifikasi selesai.</p>
              </div>
            </div>
            <button onClick={() => setIsCloudDataReady(true)} className="text-[10px] font-bold underline px-3 py-1 hover:bg-yellow-500/10 rounded-lg">LANJUTKAN OFFLINE</button>
          </div>
        )}
        {syncErrorMessage && (
          <div className="mb-4 bg-red-500/10 border border-red-500/30 p-4 rounded-2xl space-y-3 text-red-600 shadow-sm animate-in shake duration-300">
            <div className="flex items-center gap-4">
              <AlertTriangle size={24} />
              <div className="flex-1">
                <p className="font-bold text-sm uppercase">SUPABASE SYNC ALERT</p>
                <p className="text-[10px] opacity-90 break-words font-mono font-bold">{syncErrorMessage}</p>
                <p className="text-[10px] mt-1 italic text-red-500/80">Tips: Gunakan tombol 'PERBAIKI' di bawah jika strukur database bermasalah.</p>
              </div>
            </div>
            <div className="pt-2 border-t border-red-500/20 flex flex-wrap gap-2">
              <button onClick={() => setShowSqlFix(!showSqlFix)} className="flex items-center gap-1.5 text-[10px] font-bold bg-red-600 text-white px-3 py-1.5 rounded-lg hover:bg-red-700 transition">
                <Code2 size={12} /> {showSqlFix ? 'TUTUP PANDUAN' : 'PERBAIKI STRUKTUR'}
              </button>
              <button onClick={loadFromCloud} className="flex items-center gap-1.5 text-[10px] font-bold bg-white/50 border border-red-200 px-3 py-1.5 rounded-lg hover:bg-white transition">
                <RefreshCw size={12} /> COBA LAGI (RELOAD)
              </button>
            </div>
            {showSqlFix && (
              <div className="mt-3 bg-black/95 text-cyan-400 p-4 rounded-xl font-mono text-[10px] border border-cyan-500/30 overflow-x-auto relative group shadow-2xl">
                <button onClick={copySql} className="absolute top-2 right-2 p-2 bg-cyan-500/20 rounded hover:bg-cyan-500/40 text-cyan-400 border border-cyan-500/30">
                  <Copy size={14} />
                </button>
                <p className="text-yellow-400 mb-2 font-bold flex items-center gap-1">
                   <Terminal size={12}/> SOLUSI PERBAIKAN DATABASE:
                </p>
                <ol className="list-decimal list-inside space-y-1 text-cyan-400/80 mb-4">
                  <li>Klik tombol 'Copy' di script bawah ini</li>
                  <li>Buka <strong>Supabase Dashboard</strong> (SQL Editor)</li>
                  <li>Buat <strong>New Query</strong>, tempel (Paste), lalu klik <strong>Run</strong></li>
                  <li>Pastikan query sukses, lalu klik 'COBA LAGI' di sini.</li>
                </ol>
                <div className="p-2 bg-black/50 border border-cyan-500/20 rounded max-h-40 overflow-y-auto">
                  <pre className="whitespace-pre-wrap">{SQL_FIX_SCRIPT}</pre>
                </div>
              </div>
            )}
          </div>
        )}
        {isEditingProfile && (
          <div className="mb-8 bg-white p-6 rounded-2xl shadow-sm border border-gray-100 no-print">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2"><User className="text-blue-600" /> Pengaturan Profil</h2>
              <button onClick={() => setIsEditingProfile(false)} className="text-gray-400 hover:text-gray-600"><X size={20} /></button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {Object.keys(profile).map((key) => (
