                {cloudStatus === 'syncing' ? <Loader2 className="animate-spin text-blue-600" size={16} /> : cloudStatus === 'error' ? <CloudOff className="text-red-500" size={16} /> : <Cloud className="text-green-500" size={16} />}
                <span className="text-xs font-bold uppercase">{cloudStatus}</span>
              </div>
