            <button onClick={loadFromCloud} className="w-full bg-blue-600 text-white py-3 rounded-xl hover:bg-blue-700 transition font-semibold flex items-center justify-center gap-2">
              <RefreshCw size={18} className={cloudStatus === 'syncing' ? 'animate-spin' : ''} />
              <span>Tarik Data Cloud</span>
            </button>
          </div>
          <button onClick={handleLogout} className="w-full bg-gray-100 text-gray-600 py-3 rounded-xl hover:bg-gray-200 transition font-semibold flex items-center justify-center gap-2"><LogOut size={18}/> Logout</button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen pb-20 relative">
      <header className="bg-blue-700 text-white shadow-lg no-print sticky top-0 z-50">
        <div className="container mx-auto px-4 py-4 flex flex-wrap items-center justify-between">
          <div className="flex items-center space-x-2 cursor-pointer" onClick={() => setView('main')}>
            <FileText size={28} />
            <div className="flex flex-col">
              <h1 className="text-xl font-bold tracking-tight">BCK Smart Log</h1>
              {isSuperAdmin && <div className="flex items-center gap-1 text-[8px] bg-cyan-400 text-blue-900 font-black px-1 rounded animate-pulse w-fit"><ShieldAlert size={8} /> <span>SUPER ADMIN</span></div>}
