const SQL_FIX_SCRIPT = `-- SALIN DAN JALANKAN DI SQL EDITOR SUPABASE (KLIK 'RUN'):
-- Script ini akan menghapus dan membuat ulang tabel jika strukturnya rusak.
-- PERINGATAN: Pastikan Anda sudah membackup data penting atau melakukan sync lokal.

-- 1. Tabel Profiles
CREATE TABLE IF NOT EXISTS public.profiles (
    id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
    data jsonb DEFAULT '{}'::jsonb,
    updated_at timestamptz DEFAULT now()
);

-- 2. Tabel Monthly Logs
CREATE TABLE IF NOT EXISTS public.monthly_logs (
    user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE,
    month int,
    year int,
    activities jsonb DEFAULT '[]'::jsonb,
    updated_at timestamptz DEFAULT now(),
    PRIMARY KEY (user_id, month, year)
);

-- 3. Tabel Activity DB
CREATE TABLE IF NOT EXISTS public.activity_db (
    id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
    items jsonb DEFAULT '[]'::jsonb,
    updated_at timestamptz DEFAULT now()
);

-- 4. Tabel Kaldik Data
CREATE TABLE IF NOT EXISTS public.kaldik_data (
    user_id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
    events jsonb DEFAULT '[]'::jsonb,
    updated_at timestamptz DEFAULT now()
);

-- JALANKAN INI JIKA ERROR "ON CONFLICT" TERJADI PADA TABEL YANG SUDAH ADA:
-- ALTER TABLE public.kaldik_data ADD CONSTRAINT kaldik_data_pkey PRIMARY KEY (user_id);
-- ALTER TABLE public.monthly_logs ADD CONSTRAINT monthly_logs_pkey PRIMARY KEY (user_id, month, year);

-- Aktifkan RLS
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.monthly_logs ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.activity_db ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.kaldik_data ENABLE ROW LEVEL SECURITY;

-- Policy Akses (Hanya pemilik data)
DO $$ 
BEGIN
    DROP POLICY IF EXISTS "Access Own Profiles" ON public.profiles;
    CREATE POLICY "Access Own Profiles" ON public.profiles FOR ALL USING (auth.uid() = id);

    DROP POLICY IF EXISTS "Access Own Logs" ON public.monthly_logs;
    CREATE POLICY "Access Own Logs" ON public.monthly_logs FOR ALL USING (auth.uid() = user_id);

    DROP POLICY IF EXISTS "Access Own DB" ON public.activity_db;
    CREATE POLICY "Access Own DB" ON public.activity_db FOR ALL USING (auth.uid() = id);

    DROP POLICY IF EXISTS "Access Own Kaldik" ON public.kaldik_data;
    CREATE POLICY "Access Own Kaldik" ON public.kaldik_data FOR ALL USING (auth.uid() = user_id);
END $$;`;

const LoginView: React.FC = () => {
