    e.preventDefault();
    setLoading(true);
    setErrorMsg(null);
    setAuthMsg(isRegister ? 'Creating Protocol...' : 'Verifying Credentials...');

    try {
      let result;
      // Fixed: Used (supabase.auth as any) to bypass missing methods on SupabaseAuthClient type
      if (isRegister) {
