const SQL_FIX_SCRIPT = `-- SALIN DAN JALANKAN DI SQL EDITOR SUPABASE:

-- 1. Tabel Profiles (Pastikan Primary Key 'id' ada)
CREATE TABLE IF NOT EXISTS public.profiles (id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE);
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS data jsonb DEFAULT '{}'::jsonb;
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS updated_at timestamptz DEFAULT now();

-- 2. Tabel Monthly Logs (PK Gabungan: user_id, month, year)
CREATE TABLE IF NOT EXISTS public.monthly_logs (
    user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE,
    month int,
    year int,
    activities jsonb DEFAULT '[]'::jsonb,
    updated_at timestamptz DEFAULT now(),
    PRIMARY KEY (user_id, month, year)
);

-- 3. Tabel Activity DB (Pastikan Primary Key 'id' ada)
CREATE TABLE IF NOT EXISTS public.activity_db (id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE);
ALTER TABLE public.activity_db ADD COLUMN IF NOT EXISTS items jsonb DEFAULT '[]'::jsonb;
ALTER TABLE public.activity_db ADD COLUMN IF NOT EXISTS updated_at timestamptz DEFAULT now();

-- 4. Tabel Kaldik Data (PERBAIKAN ERROR ON CONFLICT: Pastikan 'user_id' adalah Primary Key)
-- Jika tabel sudah ada tanpa PK, kita hapus dulu atau paksa PK.
DO $$ 
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'kaldik_data_pkey') THEN
        ALTER TABLE IF EXISTS public.kaldik_data ADD PRIMARY KEY (user_id);
    END IF;
EXCEPTION WHEN OTHERS THEN
    CREATE TABLE IF NOT EXISTS public.kaldik_data (
        user_id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
        events jsonb DEFAULT '[]'::jsonb,
        updated_at timestamptz DEFAULT now()
    );
END $$;

-- Referensi struktur tabel kaldik_events (Opsional - Global)
-- CREATE TABLE IF NOT EXISTS public.kaldik_events (
--    pengenal bigint primary key generated always as identity,
--    tanggal_acara date,
--    nama text,
--    dibuat_pada timestamptz default now()
-- );

-- Aktifkan RLS & Policy
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.monthly_logs ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.activity_db ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.kaldik_data ENABLE ROW LEVEL SECURITY;

-- Jalankan Policy (Hanya bisa akses data sendiri)
DO $$ 
BEGIN
    DROP POLICY IF EXISTS "Own Profiles" ON public.profiles;
    CREATE POLICY "Own Profiles" ON public.profiles FOR ALL USING (auth.uid() = id);

    DROP POLICY IF EXISTS "Own Logs" ON public.monthly_logs;
    CREATE POLICY "Own Logs" ON public.monthly_logs FOR ALL USING (auth.uid() = user_id);

    DROP POLICY IF EXISTS "Own DB" ON public.activity_db;
    CREATE POLICY "Own DB" ON public.activity_db FOR ALL USING (auth.uid() = id);

    DROP POLICY IF EXISTS "Own Kaldik" ON public.kaldik_data;
    CREATE POLICY "Own Kaldik" ON public.kaldik_data FOR ALL USING (auth.uid() = user_id);
END $$;`;

