        result = await (supabase.auth as any).signInWithPassword({ email, password });
      }

      if (result.error) throw result.error;

      if (isRegister && !result.data.session) {
        setLoading(false);
        setAuthMsg('Verification Sent to Email');
        alert("Pendaftaran berhasil! Silakan cek email Anda untuk verifikasi.");
      } else {
        setAuthMsg(email.toLowerCase() === SUPER_ADMIN_EMAIL ? 'SUPER ADMIN AUTHORIZED' : 'USER AUTHORIZED');
      }
    } catch (err: any) {
      setLoading(false);
      // Handle fetch failure at login
      if (err.message === "Failed to fetch") {
        setErrorMsg("Koneksi gagal. Pastikan project Supabase tidak 'Paused' di Dashboard.");
      } else {
        setErrorMsg(err.message);
      }
      setAuthMsg('Accessing Central System');
    }
  };

  return (
    <div className="min-h-screen cyber-bg flex items-center justify-center p-4 relative overflow-hidden font-mono text-cyan-400">
       <div className="absolute inset-0 pointer-events-none opacity-10 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] z-10 bg-[length:100%_2px,3px_100%]"></div>
      <div className="max-w-md w-full relative z-20">
        <div className="bg-black/80 backdrop-blur-xl border-2 border-cyan-500 rounded-3xl p-8 shadow-[0_0_50px_rgba(0,243,255,0.2)]">
          <div className="text-center mb-8">
            <div className="inline-flex p-4 bg-cyan-500/10 rounded-full mb-4 border border-cyan-500/30 animate-pulse">
              <Terminal className="text-cyan-400" size={40} />
            </div>
            <h1 className="text-3xl font-bold text-white mb-2 glitch-text tracking-widest" data-text="BCK SMART LOG">BCK SMART LOG</h1>
            <p className={`text-xs uppercase tracking-[0.3em] transition-colors duration-500 ${loading ? 'text-yellow-400' : 'text-cyan-400/60'}`}>
              {authMsg}
            </p>
          </div>
          <form onSubmit={handleAuth} className="space-y-6">
            <div>
              <label className="block text-cyan-400 text-[10px] uppercase tracking-widest mb-2 font-bold">Protocol Email</label>
              <div className="relative">
                <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full cyber-input rounded-xl px-4 py-3 pl-11 text-sm" placeholder="name@example.com" required />
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-cyan-400/50" size={18} />
              </div>
            </div>
            <div>
              <label className="block text-cyan-400 text-[10px] uppercase tracking-widest mb-2 font-bold">Security Key</label>
              <div className="relative">
                <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full cyber-input rounded-xl px-4 py-3 pl-11 text-sm" placeholder="••••••••" required />
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-cyan-400/50" size={18} />
              </div>
            </div>
            {errorMsg && (
              <div className="bg-red-500/10 border border-red-500/50 p-3 rounded-xl text-red-400 text-[10px] flex items-center gap-2 animate-bounce uppercase">
                <ShieldCheck size={14} /> <span>ERROR: {errorMsg}</span>
              </div>
            )}
            <button type="submit" disabled={loading} className="w-full neon-btn bg-transparent border border-cyan-500 text-cyan-400 py-4 rounded-xl font-bold uppercase tracking-[0.5em] text-xs flex items-center justify-center gap-3">
              {loading ? <Loader2 className="animate-spin" size={18} /> : (
                <>{isRegister ? <UserPlus size={18} /> : <Cpu size={18} />}<span>{isRegister ? 'Register' : 'Execute Sync'}</span></>
              )}
            </button>
          </form>
          <div className="mt-8 pt-6 border-t border-cyan-500/20 text-center">
             <button onClick={() => setIsRegister(!isRegister)} className="text-[10px] text-cyan-400/60 hover:text-cyan-400 uppercase tracking-widest transition-colors underline decoration-cyan-500/30 underline-offset-4">
              {isRegister ? 'Already have access? Login' : 'New Protocol? Register Access'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

const ActivityDbInput = ({ onAdd }: { onAdd: (item: string) => void }) => {
  const [text, setText] = useState('');
  const handleAdd = () => {
    if (text.trim()) { onAdd(text.trim()); setText(''); }
  };
  return (
    <div className="flex gap-2 mb-6">
      <input className="flex-1 bg-gray-50 border rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" placeholder="Contoh: Mengoreksi hasil ulangan siswa..." value={text} onChange={(e) => setText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAdd()} />
      <button onClick={handleAdd} className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition active:scale-95 flex items-center justify-center"><Plus size={24} /></button>
    </div>
  );
};

const App: React.FC = () => {
  const [sessionUser, setSessionUser] = useState<any | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);
  const [isCloudDataReady, setIsCloudDataReady] = useState(false);
  const [view, setView] = useState<'main' | 'kaldik' | 'settings'>('main');
  const [showSqlFix, setShowSqlFix] = useState(false);
  const [notification, setNotification] = useState<{ message: string; type: 'success' | 'error' | null }>({ message: '', type: null });

  const [profile, setProfile] = useState<Profile>({
    name: 'ALI MAKSUM, S.Pd.I', nuptk: '3641766668110012', npk: '7880990033017', pegId: '910', jabatan: "Guru Mata Pelajaran Qur'an Hadits", school: 'MTsS Darul Huda', headmasterName: 'SALAMET MOLYONO, S.Pd', location: 'Bondowoso',
  });

  const [currentDate, setCurrentDate] = useState(new Date());
  const [logs, setLogs] = useState<MonthlyLog[]>([]);
  const [importedKaldik, setImportedKaldik] = useState<KaldikEvent[]>([]);
  const [activityDb, setActivityDb] = useState<string[]>([]);
  const [openDbRowId, setOpenDbRowId] = useState<string | null>(null);
  const [cloudStatus, setCloudStatus] = useState<'idle' | 'syncing' | 'error'>('idle');
  const [syncErrorMessage, setSyncErrorMessage] = useState<string | null>(null);

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isSuperAdmin = sessionUser?.email === SUPER_ADMIN_EMAIL;

  const showToast = (message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
    setTimeout(() => setNotification({ message: '', type: null }), 3000);
  };

  useEffect(() => {
    (supabase.auth as any).getSession().then(({ data: { session } }: any) => {
      setSessionUser(session?.user ?? null);
      setIsInitializing(false);
    });
    const { data: { subscription } } = (supabase.auth as any).onAuthStateChange((_event: any, session: any) => {
      setSessionUser(session?.user ?? null);
      if (!session) {
        setIsCloudDataReady(false);
        setLogs([]);
        setImportedKaldik([]);
        setActivityDb([]);
      }
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (!isInitializing) {
      const savedProfile = localStorage.getItem(STORAGE_KEY_PROFILE);
      if (savedProfile) setProfile(JSON.parse(savedProfile));
      const savedLogs = localStorage.getItem(STORAGE_KEY_LOGS);
      if (savedLogs) setLogs(JSON.parse(savedLogs));
      const savedKaldik = localStorage.getItem(STORAGE_KEY_KALDIK);
      if (savedKaldik) setImportedKaldik(JSON.parse(savedKaldik));
      const savedDb = localStorage.getItem(STORAGE_KEY_DB);
      if (savedDb) setActivityDb(JSON.parse(savedDb));

      if (sessionUser) loadFromCloud();
    }
  }, [sessionUser, isInitializing]);

  useEffect(() => {
    if (sessionUser && isCloudDataReady) {
      localStorage.setItem(STORAGE_KEY_KALDIK, JSON.stringify(importedKaldik));
      syncToCloud('kaldik_data', { user_id: sessionUser.id, events: importedKaldik }, 'user_id');
    }
  }, [importedKaldik, sessionUser, isCloudDataReady]);

  useEffect(() => {
    if (sessionUser && isCloudDataReady) {
      localStorage.setItem(STORAGE_KEY_DB, JSON.stringify(activityDb));
      syncToCloud('activity_db', { id: sessionUser.id, items: activityDb }, 'id');
    }
  }, [activityDb, sessionUser, isCloudDataReady]);

  useEffect(() => {
    if (sessionUser && isCloudDataReady) {
      localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
      syncToCloud('profiles', { id: sessionUser.id, data: profile }, 'id');
    }
  }, [profile, sessionUser, isCloudDataReady]);

  const loadFromCloud = async () => {
    if (!sessionUser) return;
    setCloudStatus('syncing');
    setSyncErrorMessage(null);
    try {
      const [pRes, lRes, dbRes, kRes] = await Promise.all([
        supabase.from('profiles').select('*').eq('id', sessionUser.id).maybeSingle(),
        supabase.from('monthly_logs').select('*').eq('user_id', sessionUser.id),
        supabase.from('activity_db').select('*').eq('id', sessionUser.id).maybeSingle(),
        supabase.from('kaldik_data').select('*').eq('user_id', sessionUser.id).maybeSingle()
      ]);

      if (pRes.error) console.warn("Profile fetch error:", pRes.error.message); 
      else if (pRes.data) setProfile(pRes.data.data);

      if (lRes.error) console.warn("Logs fetch error:", lRes.error.message); 
      else if (lRes.data && lRes.data.length > 0) setLogs(lRes.data.map((l: any) => ({ month: l.month, year: l.year, activities: l.activities })));

      if (dbRes.error) console.warn("DB fetch error:", dbRes.error.message);
      else if (dbRes.data) setActivityDb(dbRes.data.items);

      if (kRes.error) console.warn("Kaldik fetch error:", kRes.error.message);
      else if (kRes.data) setImportedKaldik(kRes.data.events);

      setCloudStatus('idle');
    } catch (e: any) {
      console.error("Critical cloud fetch error:", e);
      const msg = e?.message || "";
      if (msg.includes("Failed to fetch")) {
        setSyncErrorMessage("Gagal menghubungkan ke Cloud. Pastikan Project Supabase tidak 'Paused'.");
      } else {
        setSyncErrorMessage(msg || "Gagal sinkronisasi data cloud.");
      }
      setCloudStatus('error');
    } finally {
      setIsCloudDataReady(true);
    }
  };

  const syncToCloud = async (table: string, payload: any, onConflict?: string) => {
    if (!sessionUser || !isCloudDataReady) return;
    setCloudStatus('syncing');
    try {
      const conflictColumns = onConflict?.replace(/\s/g, '');
      const { error } = await supabase.from(table).upsert(
        { ...payload, updated_at: new Date().toISOString() },
        conflictColumns ? { onConflict: conflictColumns } : undefined
      );

      if (error) throw error;
      setCloudStatus('idle');
      showToast("Data Tersimpan di Cloud", "success");
    } catch (e: any) {
      const msg = e?.message || e?.details || (typeof e === 'string' ? e : JSON.stringify(e));
      console.error(`Sync failed for ${table}:`, msg);

      if (msg.includes("Failed to fetch")) {
        setSyncErrorMessage("Koneksi terputus (Failed to fetch). Periksa status project Supabase Anda.");
      } else if (msg.includes("no unique or exclusion constraint")) {
        setSyncErrorMessage(`Struktur tabel '${table}' bermasalah (PK tidak ditemukan). Klik PERBAIKI di bawah.`);
      } else {
        setSyncErrorMessage(`Sync Error (${table}): ${msg}`);
      }
      setCloudStatus('error');
    }
  };

  const handleLogout = async () => {
    await (supabase.auth as any).signOut();
    localStorage.clear();
    setIsCloudDataReady(false);
    window.location.reload();
  };

  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();
  const getDaysInMonth = (month: number, year: number) => new Date(year, month + 1, 0).getDate();

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;
        const standardDateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${i.toString().padStart(2, '0')}`;
        const kaldikEvent = importedKaldik.find(e => e.date === standardDateStr);
        activities.push({
          id: `${currentYear}-${currentMonth}-${i}`,
          date: date.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }),
          description: kaldikEvent ? kaldikEvent.name : (isSunday ? 'Minggu' : ''),
          quantity: (isSunday || kaldikEvent) ? 'LU' : '',
          isHoliday: isSunday || !!kaldikEvent
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear, importedKaldik]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    if (!sessionUser) return;
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);
    let updatedLog: MonthlyLog;
    if (logIndex === -1) {
      updatedLog = { ...currentLog };
      updatedLog.activities = updatedLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      newLogs.push(updatedLog);
      setLogs(newLogs);
    } else {
      updatedLog = { ...newLogs[logIndex] };
      updatedLog.activities = updatedLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);
      newLogs[logIndex] = updatedLog;
      setLogs(newLogs);
    }
    if (isCloudDataReady) syncToCloud('monthly_logs', { user_id: sessionUser.id, month: currentMonth, year: currentYear, activities: updatedLog.activities }, 'user_id,month,year');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      if (file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' || file.name.endsWith('.xlsx')) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          const csvText = XLSX.utils.sheet_to_csv(workbook.Sheets[workbook.SheetNames[0]]);
          const results = await scanCalendar({ extractedText: csvText });
          if (results) {
            setImportedKaldik(results);
            showToast("Kaldik berhasil diimpor", "success");
          }
          setIsScanning(false);
        };
        reader.readAsArrayBuffer(file);
      } else {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = (e.target?.result as string).split(',')[1];
          const results = await scanCalendar({ fileBase64: base64, mimeType: file.type });
          if (results) {
            setImportedKaldik(results);
            showToast("Kaldik berhasil diproses", "success");
          }
          setIsScanning(false);
        };
        reader.readAsDataURL(file);
      }
    } catch (err) { 
      setIsScanning(false); 
      showToast("Gagal memproses file", "error");
    }
  };

  const applyKaldikToLogs = () => {
    if (importedKaldik.length === 0) return;
    const newLogs = [...logs];
    importedKaldik.forEach(event => {
      const [y, m, d] = event.date.split('-').map(Number);
      const monthIndex = m - 1;
      const dateId = `${y}-${monthIndex}-${d}`;
      let targetLog = newLogs.find(l => l.month === monthIndex && l.year === y);
      if (!targetLog) {
          const daysCount = getDaysInMonth(monthIndex, y);
          const activities: Activity[] = [];
          for (let i = 1; i <= daysCount; i++) {
            const iterDate = new Date(y, monthIndex, i);
            const isSun = iterDate.getDay() === 0;
            activities.push({
              id: `${y}-${monthIndex}-${i}`, date: iterDate.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }), description: isSun ? 'Minggu' : '', quantity: isSun ? 'LU' : '', isHoliday: isSun
            });
          }
          targetLog = { month: monthIndex, year: y, activities };
          newLogs.push(targetLog);
      }
      targetLog.activities = targetLog.activities.map(a => (a.id === dateId) ? { ...a, description: event.name, isHoliday: true, quantity: 'LU' } : a);
    });
    setLogs(newLogs);
    setView('main');
    showToast("Kaldik diterapkan ke log harian", "success");
  };

  const copySql = () => {
    navigator.clipboard.writeText(SQL_FIX_SCRIPT);
    alert("Script SQL perbaikan berhasil disalin! Silakan jalankan di Supabase SQL Editor.");
  };

  if (isInitializing) {
    return <div className="min-h-screen cyber-bg flex items-center justify-center"><Loader2 className="animate-spin text-cyan-400" size={48} /></div>;
  }
  if (!sessionUser) return <LoginView />;

  const MainView = () => (
    <div className="animate-in fade-in slide-in-from-left-4 duration-300">
        {!isCloudDataReady && (
          <div className="mb-4 bg-yellow-500/10 border border-yellow-500/30 p-4 rounded-2xl flex items-center justify-between gap-4 text-yellow-600 shadow-sm">
            <div className="flex items-center gap-4">
              <RefreshCw className="animate-spin" size={24} />
              <div>
                <p className="font-bold text-sm uppercase">Menghubungkan ke Pusat Cloud...</p>
                <p className="text-[10px] opacity-70">Pastikan project Supabase aktif (tidak paused).</p>
              </div>
            </div>
            <button onClick={() => setIsCloudDataReady(true)} className="text-[10px] font-bold underline px-3 py-1 hover:bg-yellow-500/10 rounded-lg">LANJUTKAN OFFLINE</button>
          </div>
        )}
        {syncErrorMessage && (
          <div className="mb-4 bg-red-500/10 border border-red-500/30 p-4 rounded-2xl space-y-3 text-red-600 shadow-sm animate-in shake duration-300">
            <div className="flex items-center gap-4">
              <AlertTriangle size={24} />
              <div className="flex-1">
                <p className="font-bold text-sm uppercase">SUPABASE SYNC ALERT</p>
                <p className="text-[10px] opacity-90 break-words font-mono font-bold">{syncErrorMessage}</p>
                <p className="text-[10px] mt-1 italic text-red-500/80">Tips: Jika error 'Failed to fetch' terus muncul, cek Dashboard Supabase (Project mungkin sedang Paused/Terhenti).</p>
              </div>
            </div>
            <div className="pt-2 border-t border-red-500/20 flex flex-wrap gap-2">
              <button onClick={() => setShowSqlFix(!showSqlFix)} className="flex items-center gap-1.5 text-[10px] font-bold bg-red-600 text-white px-3 py-1.5 rounded-lg hover:bg-red-700 transition">
                <Code2 size={12} /> {showSqlFix ? 'TUTUP PANDUAN' : 'PERBAIKI DATABASE'}
              </button>
              <button onClick={loadFromCloud} className="flex items-center gap-1.5 text-[10px] font-bold bg-white/50 border border-red-200 px-3 py-1.5 rounded-lg hover:bg-white transition">
                <RefreshCw size={12} /> RE-CONNECT CLOUD
              </button>
            </div>
            {showSqlFix && (
              <div className="mt-3 bg-black/95 text-cyan-400 p-4 rounded-xl font-mono text-[10px] border border-cyan-500/30 overflow-x-auto relative group shadow-2xl">
                <button onClick={copySql} className="absolute top-2 right-2 p-2 bg-cyan-500/20 rounded hover:bg-cyan-500/40 text-cyan-400 border border-cyan-500/30">
                  <Copy size={14} />
                </button>
                <p className="text-yellow-400 mb-2 font-bold flex items-center gap-1">
                   <Terminal size={12}/> SOLUSI PERBAIKAN STRUKTUR:
                </p>
                <ol className="list-decimal list-inside space-y-1 text-cyan-400/80 mb-4">
                  <li>Klik tombol 'Copy' di script bawah ini</li>
                  <li>Buka <strong>Supabase SQL Editor</strong> di dashboard</li>
                  <li>Tempel kode lalu klik <strong>Run</strong></li>
                  <li>Klik 'RE-CONNECT CLOUD' di aplikasi ini setelah query sukses.</li>
                </ol>
                <div className="p-2 bg-black/50 border border-cyan-500/20 rounded max-h-40 overflow-y-auto">
                  <pre className="whitespace-pre-wrap">{SQL_FIX_SCRIPT}</pre>
                </div>
              </div>
            )}
          </div>
        )}
        {isEditingProfile && (
          <div className="mb-8 bg-white p-6 rounded-2xl shadow-sm border border-gray-100 no-print">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2"><User className="text-blue-600" /> Pengaturan Profil</h2>
              <button onClick={() => setIsEditingProfile(false)} className="text-gray-400 hover:text-gray-600"><X size={20} /></button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {Object.keys(profile).map((key) => (
                <div key={key}>
                  <label className="block text-xs font-semibold text-gray-500 mb-1 capitalize">{key.replace(/([A-Z])/g, ' $1').trim()}</label>
                  <input className="w-full bg-gray-50 border rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none" value={(profile as any)[key]} onChange={e => setProfile({...profile, [key as keyof Profile]: e.target.value})}/>
                </div>
              ))}
            </div>
          </div>
        )}
        <div className="mb-6 flex flex-wrap items-center justify-between gap-4 no-print">
          <div className="flex items-center bg-white border border-gray-200 rounded-2xl p-1 shadow-sm">
            <button onClick={() => setCurrentDate(new Date(currentYear, currentMonth - 1, 1))} className="p-2 hover:bg-gray-100 rounded-xl transition"><ChevronLeft size={20} /></button>
            <div className="px-6 font-bold text-gray-700 capitalize">{currentDate.toLocaleDateString('id-ID', { month: 'long', year: 'numeric' })}</div>
            <button onClick={() => setCurrentDate(new Date(currentYear, currentMonth + 1, 1))} className="p-2 hover:bg-gray-100 rounded-xl transition"><ChevronRight size={20} /></button>
          </div>
          <div className="flex gap-2">
            <button onClick={async () => { setAiLoading(true); const ideas = await suggestActivities(profile.jabatan, profile.school); if (ideas) setSuggestions(ideas); setAiLoading(false); }} disabled={aiLoading} className="flex items-center space-x-2 bg-indigo-600 text-white px-5 py-2.5 rounded-xl shadow-md hover:shadow-lg transition disabled:opacity-50">
              <Sparkles size={18} /><span>{aiLoading ? 'Berpikir...' : 'Ide AI'}</span>
            </button>
          </div>
        </div>
        {(suggestions.length > 0 || activityDb.length > 0) && (
          <div className="mb-6 p-4 bg-white border border-gray-200 rounded-2xl no-print shadow-sm animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-3"><span className="text-sm font-bold text-gray-600">Quick-Pick:</span><button onClick={() => setSuggestions([])} className="text-gray-400 hover:text-gray-600 text-sm"><X size={16}/></button></div>
            <div className="flex flex-wrap gap-2">
              {suggestions.map((s, idx) => (
                <button key={`ai-${idx}`} onClick={() => { const empty = currentLog.activities.find(a => !a.description && !a.isHoliday); if (empty) updateActivity(empty.id, { description: s, quantity: '1 Kegiatan' }); }} className="bg-indigo-50 border border-indigo-100 px-3 py-1.5 rounded-full text-xs text-indigo-600 hover:bg-indigo-600 hover:text-white transition flex items-center gap-1"><Sparkles size={10}/> {s}</button>
