      const savedLogs = localStorage.getItem(STORAGE_KEY_LOGS);
      if (savedLogs) setLogs(JSON.parse(savedLogs));
      const savedKaldik = localStorage.getItem(STORAGE_KEY_KALDIK);
      if (savedKaldik) setImportedKaldik(JSON.parse(savedKaldik));
      const savedDb = localStorage.getItem(STORAGE_KEY_DB);
      if (savedDb) setActivityDb(JSON.parse(savedDb));

      if (sessionUser) loadFromCloud();
    }
  }, [sessionUser, isInitializing]);

  useEffect(() => {
    if (sessionUser && isCloudDataReady) {
      localStorage.setItem(STORAGE_KEY_KALDIK, JSON.stringify(importedKaldik));
      syncToCloud(TABLE_KALDIK, { user_id: sessionUser.id, events: importedKaldik }, 'user_id');
    }
  }, [importedKaldik, sessionUser, isCloudDataReady]);

  useEffect(() => {
    if (sessionUser && isCloudDataReady) {
      localStorage.setItem(STORAGE_KEY_DB, JSON.stringify(activityDb));
      syncToCloud(TABLE_DB, { id: sessionUser.id, items: activityDb }, 'id');
    }
  }, [activityDb, sessionUser, isCloudDataReady]);

  useEffect(() => {
    if (sessionUser && isCloudDataReady) {
      localStorage.setItem(STORAGE_KEY_PROFILE, JSON.stringify(profile));
      syncToCloud(TABLE_PROFIL, { id: sessionUser.id, data: profile }, 'id');
    }
  }, [profile, sessionUser, isCloudDataReady]);

  const loadFromCloud = async () => {
    if (!sessionUser) return;
    setCloudStatus('syncing');
    setSyncErrorMessage(null);
    try {
      const [pRes, lRes, dbRes, kRes] = await Promise.all([
        supabase.from(TABLE_PROFIL).select('*').eq('id', sessionUser.id).maybeSingle(),
        supabase.from(TABLE_LOGS).select('*').eq('user_id', sessionUser.id),
        supabase.from(TABLE_DB).select('*').eq('id', sessionUser.id).maybeSingle(),
        supabase.from(TABLE_KALDIK).select('*').eq('user_id', sessionUser.id).maybeSingle()
      ]);

      if (pRes.error) console.warn("Profile fetch error:", pRes.error.message); 
      else if (pRes.data) setProfile(pRes.data.data);

      if (lRes.error) console.warn("Logs fetch error:", lRes.error.message); 
      else if (lRes.data && lRes.data.length > 0) setLogs(lRes.data.map((l: any) => ({ month: l.month, year: l.year, activities: l.activities })));

      if (dbRes.error) console.warn("DB fetch error:", dbRes.error.message);
      else if (dbRes.data) setActivityDb(dbRes.data.items);

      if (kRes.error) console.warn("Kaldik fetch error:", kRes.error.message);
      else if (kRes.data) setImportedKaldik(kRes.data.events);

      setCloudStatus('idle');
    } catch (e: any) {
      console.error("Critical cloud fetch error:", e);
      const msg = e?.message || "";
      if (msg.includes("Failed to fetch")) {
        setSyncErrorMessage("Gagal menghubungkan ke Supabase. Pastikan Project tidak 'Paused' di Dashboard.");
      } else {
        setSyncErrorMessage(msg || "Gagal sinkronisasi data.");
      }
      setCloudStatus('error');
    } finally {
      setIsCloudDataReady(true);
    }
  };

  const syncToCloud = async (table: string, payload: any, onConflict?: string) => {
    if (!sessionUser || !isCloudDataReady) return;
    setCloudStatus('syncing');
    try {
      const conflictColumns = onConflict?.replace(/\s/g, '');
      const { error } = await supabase.from(table).upsert(
        { ...payload, updated_at: new Date().toISOString() },
        conflictColumns ? { onConflict: conflictColumns } : undefined
      );

      if (error) throw error;
      setCloudStatus('idle');
      showToast("Tersinkron", "success");
    } catch (e: any) {
      const msg = e?.message || e?.details || (typeof e === 'string' ? e : JSON.stringify(e));
      console.error(`Sync failed for ${table}:`, msg);

      if (msg.includes("Failed to fetch")) {
        setSyncErrorMessage("Koneksi terputus. Pastikan status project Supabase Anda aktif.");
      } else if (msg.includes("no unique or exclusion constraint")) {
        setSyncErrorMessage(`Tabel '${table}' tidak memiliki Primary Key yang benar. Gunakan tombol 'PERBAIKI' di bawah.`);
      } else {
        setSyncErrorMessage(`Sync Error (${table}): ${msg}`);
      }
      setCloudStatus('error');
    }
  };

  const handleLogout = async () => {
    await (supabase.auth as any).signOut();
    localStorage.clear();
    setIsCloudDataReady(false);
    window.location.reload();
  };

  const currentMonth = currentDate.getMonth();
  const currentYear = currentDate.getFullYear();
  const getDaysInMonth = (month: number, year: number) => new Date(year, month + 1, 0).getDate();

  const getLogForCurrentMonth = useCallback(() => {
    let log = logs.find(l => l.month === currentMonth && l.year === currentYear);
    if (!log) {
      const days = getDaysInMonth(currentMonth, currentYear);
      const activities: Activity[] = [];
      for (let i = 1; i <= days; i++) {
        const date = new Date(currentYear, currentMonth, i);
        const isSunday = date.getDay() === 0;
        const standardDateStr = `${currentYear}-${(currentMonth + 1).toString().padStart(2, '0')}-${i.toString().padStart(2, '0')}`;
        const kaldikEvent = importedKaldik.find(e => e.date === standardDateStr);
        activities.push({
          id: `${currentYear}-${currentMonth}-${i}`,
          date: date.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }),
          description: kaldikEvent ? kaldikEvent.name : (isSunday ? 'Minggu' : ''),
          quantity: (isSunday || kaldikEvent) ? 'LU' : '',
          isHoliday: isSunday || !!kaldikEvent
        });
      }
      log = { month: currentMonth, year: currentYear, activities };
    }
    return log;
  }, [logs, currentMonth, currentYear, importedKaldik]);

  const currentLog = getLogForCurrentMonth();

  const updateActivity = (id: string, updates: Partial<Activity>) => {
    if (!sessionUser) return;
    const newLogs = [...logs];
    const logIndex = newLogs.findIndex(l => l.month === currentMonth && l.year === currentYear);
    let updatedLog: MonthlyLog;

    // Logic for finding target log
    if (logIndex === -1) {
      updatedLog = { ...currentLog };
    } else {
      updatedLog = { ...newLogs[logIndex] };
    }

    // Identify current activity for auto-fill logic
    const targetActivity = updatedLog.activities.find(a => a.id === id);
    if (!targetActivity) return;

    // Apply main update
    updatedLog.activities = updatedLog.activities.map(a => a.id === id ? { ...a, ...updates } : a);

    // AUTO-FILL FEATURE: Jika deskripsi diisi, isi deskripsi yang sama untuk hari yang sama di minggu-minggu berikutnya
    if (updates.description !== undefined && updates.description !== '') {
      const [y, m, d] = id.split('-').map(Number);
      const dateObj = new Date(y, m, d);
      const dayOfWeek = dateObj.getDay();

      let fillCount = 0;
      updatedLog.activities = updatedLog.activities.map(a => {
        const [ay, am, ad] = a.id.split('-').map(Number);
        const aDate = new Date(ay, am, ad);

        // Aturan: Hari yang sama (Misal: Senin), Tanggal lebih besar (Minggu berikutnya), Bukan hari libur, dan deskripsi masih kosong
        if (ad > d && aDate.getDay() === dayOfWeek && !a.isHoliday && !a.description) {
          fillCount++;
          return { ...a, description: updates.description || '', quantity: updates.quantity || a.quantity || '1 Kegiatan' };
        }
        return a;
      });

      if (fillCount > 0) {
        showToast(`Jadwal mingguan otomatis terisi (${fillCount} baris)`, "success");
      }
    }

    // Save state
    if (logIndex === -1) {
      newLogs.push(updatedLog);
    } else {
      newLogs[logIndex] = updatedLog;
    }
    setLogs(newLogs);

    if (isCloudDataReady) syncToCloud(TABLE_LOGS, { user_id: sessionUser.id, month: currentMonth, year: currentYear, activities: updatedLog.activities }, 'user_id,month,year');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsScanning(true);
    try {
      if (file.type === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' || file.name.endsWith('.xlsx')) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array' });
          const csvText = XLSX.utils.sheet_to_csv(workbook.Sheets[workbook.SheetNames[0]]);
          const results = await scanCalendar({ extractedText: csvText });
          if (results) {
            setImportedKaldik(results);
            showToast("Kaldik diimpor", "success");
          }
          setIsScanning(false);
        };
        reader.readAsArrayBuffer(file);
      } else {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = (e.target?.result as string).split(',')[1];
          const results = await scanCalendar({ fileBase64: base64, mimeType: file.type });
          if (results) {
            setImportedKaldik(results);
            showToast("Kaldik diproses", "success");
          }
          setIsScanning(false);
        };
        reader.readAsDataURL(file);
      }
    } catch (err) { 
      setIsScanning(false); 
      showToast("Gagal memproses", "error");
    }
  };

  const applyKaldikToLogs = () => {
    if (importedKaldik.length === 0) return;
    const newLogs = [...logs];
    importedKaldik.forEach(event => {
      const [y, m, d] = event.date.split('-').map(Number);
      const monthIndex = m - 1;
      const dateId = `${y}-${monthIndex}-${d}`;
      let targetLog = newLogs.find(l => l.month === monthIndex && l.year === y);
      if (!targetLog) {
          const daysCount = getDaysInMonth(monthIndex, y);
          const activities: Activity[] = [];
          for (let i = 1; i <= daysCount; i++) {
            const iterDate = new Date(y, monthIndex, i);
            const isSun = iterDate.getDay() === 0;
            activities.push({
              id: `${y}-${monthIndex}-${i}`, date: iterDate.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }), description: isSun ? 'Minggu' : '', quantity: isSun ? 'LU' : '', isHoliday: isSun
            });
          }
          targetLog = { month: monthIndex, year: y, activities };
          newLogs.push(targetLog);
      }
      targetLog.activities = targetLog.activities.map(a => (a.id === dateId) ? { ...a, description: event.name, isHoliday: true, quantity: 'LU' } : a);
    });
    setLogs(newLogs);
    setView('main');
    showToast("Kaldik diterapkan", "success");
  };

